window.TPP_DAILY=window.TPP_DAILY||{};window.TPP_DAILY["threes"]={"aug":{"theme":"Welcome to Our Den","weeks":[{"label":"Week 1 — Our New Den","days":[{"day":"Monday","focus":"Our Home Den","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Home Den Tour","d":"Let your child play tour guide and walk you through your home, naming each room out loud. Naming familiar spaces builds vocabulary — and it helps a brand-new school year feel a little less big."},{"t":"Cozy Reading Nook","d":"Pile pillows and a blanket in a corner and crown it your family reading den. Read one book there together tonight — a calm spot of their own makes back-to-school week feel safe."}]},{"day":"Tuesday","focus":"Walking Feet","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Walking Feet Game","d":"Call out “walking feet” and “running feet” and switch back and forth across the living room. Practicing stop-and-go builds the self-control teachers ask for all day at school."},{"t":"Freeze and Go","d":"Turn on a song and dance, then pause the music for a freeze. Holding still for three slow seconds is real self-control practice — and it always ends in giggles."}]},{"day":"Wednesday","focus":"Letter A Week","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Tape Letter A","d":"Make a giant letter A on the floor with masking tape and let your child walk it like a balance beam, saying the letter's name at each turn. Big-body letters are the ones that stick."},{"t":"Red A Art","d":"Draw a big A on paper and let your child fill it in with red crayon — red is this month's color. Say the letter's name together while they color."}]},{"day":"Thursday","focus":"Watch and Count","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"One of Each","d":"Ask your child to bring you exactly one spoon, one sock, and one cup. One is this month's number, and fetching “just one” makes counting feel real."},{"t":"Ice Cube Watch","d":"Drop one ice cube into a red cup of warm water and watch it disappear together. Ask “where did it go?” — watching and wondering is real science for a three-year-old."}]},{"day":"Friday","focus":"My Special Spot","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Door Name Tag","d":"Help your child decorate a name card for their bedroom door, just like a cubby tag at school. Seeing their name posted says it plainly: you belong here."},{"t":"Family Jobs Talk","d":"At dinner, name one job each person does for your home den — who feeds the dog, who wipes the table. Every helper matters, even the smallest one."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these in the backpack pocket — little bits of home for a big first week.","items":["Practice the morning goodbye at home: hug, kiss, high five, wave. A rehearsed goodbye is a braver goodbye.","Point out the letter A on cereal boxes and street signs all week.","Read the Bear Phonics reader “See Me” together — three is when the decodable readers begin.","Lay out clothes the night before and let your child pick between two shirts — small choices, smoother mornings."]}},{"label":"Week 2 — New Friends","days":[{"day":"Monday","focus":"Roll and Greet","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Name Roll Ball","d":"Sit on the floor and roll a ball back and forth, saying the catcher's name each time it rolls. It's how teachers help new friends learn names — and it works at home too."},{"t":"Wave Big Hello","d":"Practice big friendly hellos in the mirror — wave, smile, and say “Hi, I'm…” with their name. Rehearsing at home makes the real thing easier on the playground."}]},{"day":"Tuesday","focus":"Friend Name Song","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Sing Their Names","d":"Sing your child's new classmates' names to the tune of “The More We Get Together.” Names set to music are easier to remember — ask which friend they played with today."},{"t":"Friendship Band","d":"Cut a paper strip, let your child decorate it, and tape it into a bracelet for a friend or family member. Making something to give away is friendship practice."}]},{"day":"Wednesday","focus":"Letter B Buddy","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"B Basket Collect","d":"Hand your child a basket and gather things that start with B — ball, book, banana, bear. Say the B sound together as each one drops in."},{"t":"Bear Says B","d":"Play a quick listening game: say bear, ball, cat, bus, and have your child clap only for the B words. Listening for first sounds is pre-reading gold."}]},{"day":"Thursday","focus":"Counting Friends","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"Count Our People","d":"Count the people in your family, then the friends your child names from school, using one finger per person. Whose group is bigger? Comparing groups is early math."},{"t":"Helper Spotting","d":"On a walk or drive, point out the people who help your neighborhood run — mail carrier, cashier, crossing guard. Friends and helpers are your child's first idea of community."}]},{"day":"Friday","focus":"Alike and Different","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Same and Different","d":"Stand at the mirror together and find two ways you're alike and two ways you're different. Noticing differences kindly is how empathy starts."},{"t":"Handprint Pair","d":"Trace your hand and your child's hand side by side and compare — whose is bigger, whose is smaller? Hang it up as this week's friendship art."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Friendship grows at home first — here are this week's little helpers.","items":["Ask “who did you play with today?” at pickup — one small question keeps the friend stories coming.","Read a book about friends at bedtime, and reread “See Me” together this week.","Point out the letter B at the grocery store — bananas, bread, boxes.","Hold a five-minute playdate rehearsal with stuffed animals: hi, share, take turns, bye."]}},{"label":"Week 3 — Rules & Routines","days":[{"day":"Monday","focus":"Clean-Up Champs","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Beat the Song","d":"Sing a clean-up song and see if the toys make it to the bin before it ends. Racing the song turns tidy-up from a battle into a game."},{"t":"Toy Basket Toss","d":"Set a basket in the middle of the room and let your child toss soft toys in from a step away as they clean. Aim, throw, tidy — three skills in one."}]},{"day":"Tuesday","focus":"Picture Schedule","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Draw Our Evening","d":"Draw quick stick pictures of your evening — dinner, bath, books, bed — and tape them where your child can see. Point to each step as it comes; predictable routines calm busy brains."},{"t":"Photo Routine Strip","d":"Snap photos of your child doing each bedtime step and scroll through them in order at night. Kids love starring in their own how-to guide."}]},{"day":"Wednesday","focus":"First, Next, Last","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Sandwich Order","d":"Make a snack together and narrate the order: first the bread, next the filling, last the top. Then ask your child to tell it back. Sequencing is math and storytelling in one bite."},{"t":"Mixed-Up Story","d":"Retell today out of order — “first bed, next breakfast?” — and let your child fix you. Catching the mix-up shows real sequence thinking, and threes love correcting grown-ups."}]},{"day":"Thursday","focus":"Why We Wash","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Pepper Soap Trick","d":"Sprinkle pepper on a bowl of water, then let your child touch the middle with a soapy finger and watch the “germs” zoom away. Now hand-washing has a why."},{"t":"Twenty-Second Scrub","d":"Wash hands together while singing the ABC song, scrubbing tops, palms, and between fingers. C is for clean — point out the letter C on the soap bottle if you spot one."}]},{"day":"Friday","focus":"Calm and Kind","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Cozy Calm Spot","d":"Build a small calm-down spot with a pillow and a stuffed friend, and practice using it while everyone is happy. Practiced calm is there waiting when the storm comes."},{"t":"Draw a Rule","d":"Ask your child to pick one family rule — gentle hands, walking feet — and draw a picture of it for the fridge. Kids follow rules better when they helped make them."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Routines are the quiet heroes of preschool — these keep them strong at home.","items":["Keep goodbye short and the same every day — same words, same hug, then go.","Practice the C sound around the house: cup, car, cat, clean.","Read one book at the same time each night — the routine is the magic, and “See Me” makes a quick one.","When a rule wobbles, name the feeling first (“you're mad”), then the rule (“and we use gentle hands”)."]}},{"label":"Week 4 — All About School","days":[{"day":"Monday","focus":"School Skills Course","domains":["Physical Development","Social Studies"],"opts":[{"t":"Backpack Obstacle Course","d":"Set up a course: zip the backpack, hang it on a chair, walk a tape line, sit criss-cross. School skills are body skills — practice makes the classroom feel easy."},{"t":"Spot Our School","d":"On your next drive or walk, point out your child's school and the places near it — the park, the store. School is part of a neighborhood, and knowing the way builds pride."}]},{"day":"Tuesday","focus":"All About Me","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Me Interview","d":"Play reporter: ask your child their name, age, and favorite thing, then let them interview you back. Practicing “about me” talk builds confidence for sharing at school."},{"t":"Show and Tell Practice","d":"Let your child pick one treasure and tell you three things about it while you listen like an audience. First show-and-tells feel big — a little rehearsal shrinks them."}]},{"day":"Wednesday","focus":"Sort It Out","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Supply Sort","d":"Pour out the crayon bin and sort together — crayons here, markers there, pencils in the cup. Sorting by kind is real preschool math with a tidy bonus."},{"t":"Shape and Color Sort","d":"Gather red things and not-red things into two piles, then find every circle in the mix. Red and circle are this month's stars — let your child be the judge of what belongs."}]},{"day":"Thursday","focus":"Five Senses","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Senses Walk","d":"Take a slow walk and collect with your senses: two things you hear, two you see, one you smell. Stopping to notice is the heart of science."},{"t":"Mystery Sock Feel","d":"Hide a spoon, a block, or a cotton ball in a sock and let your child guess by feel alone. Touch-only guessing wakes up describing words too."}]},{"day":"Friday","focus":"I Love School","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Self-Portrait Artist","d":"Set out a mirror and crayons and let your child draw themselves for the wall. Three-year-old self-portraits are wonderfully wild — label it with their name and the date."},{"t":"School Love List","d":"At dinner, everyone finishes the sentence “I love school because…” — then write your child's answer under their portrait. Naming good feelings helps them grow."}]}],"homeden":{"title":"The Home Den — This Week","lead":"One month in — time to notice how far your little one has already come.","items":["Review all three letters this month — A, B, C — on signs, boxes, and shirts.","Read “See Me” once more and let your child chime in on the parts they remember — that confidence is the whole point at three.","Trace a plate onto paper and let your child color the circle red — shape, color, done.","Celebrate the first month: tell your child one specific brave thing you saw them do."]}}]},"sep":{"theme":"All About Me & My Family","weeks":[{"label":"Week 1 — This Is Me","days":[{"day":"Monday","focus":"Big Me","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Chalk Body Trace","d":"Have your child lie on the driveway while you trace them with sidewalk chalk, then let them add hair, a face, and clothes. Seeing themselves life-size is a thrill at three."},{"t":"Giant Paper Me","d":"Tape grocery bags or wrapping paper together, trace your child on top, and let them decorate. Hang the finished kid on a door — instant favorite artwork."}]},{"day":"Tuesday","focus":"My Name and S","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Name Card Trace","d":"Write your child's name in big letters and let them trace it with a finger, then a crayon. If their name has an S in it, celebrate — Ss is this month's letter."},{"t":"S Snake Sound","d":"Draw a wiggly snake shaped like the letter S and slide a finger along it saying “sss.” It's a sound kids love to hiss — let them teach it to a stuffed animal."}]},{"day":"Wednesday","focus":"Count Me","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Body Part Count","d":"Count together: two eyes, one nose, ten toes — touching each part as you go. Two is this month's number, so look for body parts that come in pairs."},{"t":"Slow-Mo Head Shoulders","d":"Sing “Head, Shoulders, Knees and Toes” in slow motion, then at silly speed. Naming body parts in song builds vocabulary — the speed round builds the fun."}]},{"day":"Thursday","focus":"My Five Senses","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Taste Test Tray","d":"Set out three tiny tastes — something sweet, something sour, something crunchy — and let your child describe each one. No forcing bites; sniffing counts as science too."},{"t":"Sound Detective","d":"Sit very still together, close your eyes, and name every sound you hear for one minute — the fridge hum, a bird, a car. Careful listening is a whole-body workout."}]},{"day":"Friday","focus":"I Am Special","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Special Because Chat","d":"At dinner, everyone finishes “I am special because…” — then write your child's answer and tuck it in their lunchbox for tomorrow. Kids stand taller when their words are treasured."},{"t":"Where I Live","d":"Practice saying your child's full name and the town where they live, like a little introduction. Knowing who I am and where I'm from is a three-year-old's first geography."}]}],"homeden":{"title":"The Home Den — This Week","lead":"All about your favorite little person — easy ways to keep it going at home.","items":["Trace the letter S in a pan of dry rice with a fingertip — letters you can feel stick best.","Look for twos all week: shoes, socks, ears, eyes. Two is the number of the month.","Read “See Me” together and let your child point to each word — pointing is early reading.","Stick an orange square on the fridge — this month's color and shape in one sticky note."]}},{"label":"Week 2 — My Family","days":[{"day":"Monday","focus":"Family Jobs","domains":["Social Studies","Physical Development"],"opts":[{"t":"Little Helper Play","d":"Act out family jobs together — sweep, stir, fold a washcloth — then let your child do one for real. Threes love pretend scripts, and real helping builds real pride."},{"t":"Sock Delivery Service","d":"Load matched socks into a basket and let your child deliver each pair to the right person's room. Carrying, sorting, and helping — a whole workout disguised as a job."}]},{"day":"Tuesday","focus":"Draw My Family","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Family Portrait Draw","d":"Ask your child to draw everyone in your family, then write down exactly what they tell you about each person. Their words next to their art is a keepsake and a literacy lesson."},{"t":"Family Name Game","d":"Give a clue — “this person makes the best pancakes” — and let your child guess the family member, then swap turns. Talking about people we love grows describing words fast."}]},{"day":"Wednesday","focus":"Tall and Short","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Family Line-Up","d":"Line up the family from tallest to shortest — people if they're home, their shoes if they're not. Ordering by size is real math thinking, no worksheet required."},{"t":"Block Tower Me","d":"Build a tower as tall as your child's knee, then their hip — how many blocks each time? Measuring with toys makes “taller” and “shorter” mean something."}]},{"day":"Thursday","focus":"Families Compare","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Photo Look Close","d":"Look through family photos and notice together — who has curly hair, who wears glasses, who has Grandma's smile? Spotting alike-and-different is gentle science and family love at once."},{"t":"All Kinds of Families","d":"While reading tonight, point out the families in your books — big, small, all different — and talk about who is in yours. Every family is its own kind of wonderful."}]},{"day":"Friday","focus":"Family Stories","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"When You Were Little","d":"Tell your child a two-minute story about the day they were born or something silly they did as a baby. Kids ask for these on repeat — family stories build belonging."},{"t":"Grandparent Call","d":"Call a grandparent or favorite relative and let your child tell them one thing about their week. Real conversations with people who love them are language practice with heart."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Family is the first classroom — these keep the lessons warm.","items":["Decorate a paper frame around a favorite family photo — this week's fridge art.","Sort laundry together and ask “whose shirt is this?” — sorting by person is math and helpfulness.","Spot the letter S in the names of people you love and hiss the snake sound together.","Two hugs at bedtime — one for each cheek. Two is still the number of the month."]}},{"label":"Week 3 — My Feelings","days":[{"day":"Monday","focus":"Feelings in Motion","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Feelings Freeze Dance","d":"Dance to music and, when it stops, call out a feeling — mad, happy, sleepy — for everyone to act out frozen. Naming feelings with the whole body makes them easier to name in real moments."},{"t":"Stomp It Out","d":"When wiggles are big, try “mad stomps” across the room together, then “calm tiptoes” back. Moving through a feeling teaches that feelings change — and pass."}]},{"day":"Tuesday","focus":"Feelings Words","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Your Feelings Matter","d":"Read a feelings book together — Mrs. Bear's own “Your Feelings Matter” is made for this week — and pause to ask “has that ever happened to you?” Stories give feelings their names."},{"t":"How We Comfort","d":"Talk about what each family member does to feel better — Daddy takes a walk, sister hugs her bear. Learning that everyone has feelings makes home feel like a team."}]},{"day":"Wednesday","focus":"Feelings Graph","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Face Chart Check-In","d":"Draw three faces — happy, sad, mad — on paper and let everyone place a cereal piece on today's feeling at dinner. Count each column together: your first family graph."},{"t":"Smile Tally","d":"Keep a tally today: every time someone laughs, add a mark to a paper on the fridge. Count the marks at bedtime and guess whether tomorrow can beat it."}]},{"day":"Thursday","focus":"Heartbeat Science","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Jump and Feel","d":"Have your child feel their heartbeat sitting still, then again after ten big jumps. Faster? That's the body hard at work — and a question worth wondering about together."},{"t":"Belly Balloon Breaths","d":"Lie down with a stuffed animal on your child's belly and watch it rise and fall with slow breaths. Big feelings shrink when the breath slows — let the animal ride the waves."}]},{"day":"Friday","focus":"Feelings Art","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Color a Feeling","d":"Ask “what color is happy?” and let your child scribble it big, then try mad and calm too. There are no wrong answers — art gives feelings somewhere safe to go."},{"t":"Paper Plate Faces","d":"Draw a happy face on one paper plate and a grumpy face on another, and let your child hold up the one that matches how each character feels during tonight's story."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Feelings week — the most important unit of the whole year, honestly.","items":["Name the feeling before fixing the problem: “you're frustrated” works better than “you're fine.”","Practice the S sound with feeling words: sad, silly, scared, safe.","Make an orange square “break card” your child can hand you when they need a calm minute.","Catch one kind moment a day and say exactly what you saw: “You shared your truck. That was kind.”"]}},{"label":"Week 4 — My Friends","days":[{"day":"Monday","focus":"Play Together","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Blanket Ball Bounce","d":"Hold a blanket by the corners with your child and bounce a soft toy on top, working together to keep it from falling. Teamwork you can feel in your hands."},{"t":"Mirror Moves","d":"Stand face to face and copy each other's moves like a mirror — slow arms, silly faces, one-foot balance. Taking turns being the leader is friendship practice."}]},{"day":"Tuesday","focus":"A Friend Is","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"What Friends Do","d":"Finish the sentence together: “a friend is someone who…” Write your child's answers down and hang the list where they can see it. Their own words make the best kindness rules."},{"t":"Kindness Mail","d":"Help your child draw a picture for a friend or neighbor and deliver it to their mailbox or backpack. Communities are built out of small kindnesses — even folded-paper ones."}]},{"day":"Wednesday","focus":"Count and Compare","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Snack Math Share","d":"Count out crackers — two for you, two for me — until the plate is empty. Fair-share counting is the math that threes care about most."},{"t":"Stuffed Animal Party","d":"Set up a pretend party and count the guests, then the cups — is there one for each? Matching one-to-one is a big math idea hiding inside pretend play."}]},{"day":"Thursday","focus":"Sink or Float","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Bath Toy Test","d":"At bath time — staying within arm's reach — guess together whether each toy will sink or float, then test and sort them. Guess-then-check is the whole scientific method, pint-sized."},{"t":"Heavy or Light","d":"Hold a spoon in one hand and a shoe in the other — which feels heavier? Let your child test pairs of objects around the room and report back like a scientist."}]},{"day":"Friday","focus":"Friendship Art","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Handprint Wreath","d":"Trace everyone's hands, cut them out together with safety scissors, and tape them in a circle on the door. A wreath made of the hands that love them — the month in one picture."},{"t":"Friend Thank-You Card","d":"Make a card for someone who was kind this month and let your child dictate the message while you write. Saying thank you out loud plants gratitude that sticks."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Friendship skills are built one small rehearsal at a time.","items":["Rehearse joining play with stuffed animals: “Can I play too?” Practice makes the playground easier.","Read “See Me” and cheer the words your child says alone — three is when reading begins.","Count in twos this week: shoes at the door, crackers on the plate.","Spot squares everywhere — windows, crackers, napkins — and three orange things too."]}}]},"oct":{"theme":"The Great Outdoors","weeks":[{"label":"Week 1 — Leaves & Trees","days":[{"day":"Monday","focus":"Leaf Jumping","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Leaf Pile Jump","d":"Gather a small pile of leaves and let your child jump in, stomp through, and toss them up. Big outdoor play builds strong bodies — and fall memories."},{"t":"Tree Pose Wobble","d":"Stand like trees together — arms up for branches, one foot lifted for a windy day. How long can your little tree balance? Count the seconds out loud."}]},{"day":"Tuesday","focus":"Describe a Leaf","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Leaf Detective","d":"Pick up one leaf and describe it together — its color, its shape, its crunch — then find a leaf that's different. Describing words grow fastest outdoors."},{"t":"T Is Tree","d":"Trace a letter T in the dirt with a stick, then point up: T is for tree. Say the sound while touching the trunk — letters learned outside stick around."}]},{"day":"Wednesday","focus":"Count to Three","domains":["Mathematical Thinking","Creative Expression"],"opts":[{"t":"Three Leaf Line-Up","d":"Collect three leaves and line them up biggest to smallest, counting as you go. Three is this month's number — let your child arrange, count, and rearrange."},{"t":"Leaf Rubbing Art","d":"Put a leaf under paper and rub the side of a brown crayon over it until the leaf appears like magic. Brown is October's color — make a set of three."}]},{"day":"Thursday","focus":"Why Leaves Fall","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Falling Leaf Watch","d":"Sit under a tree for a few quiet minutes and watch for a falling leaf. Wonder out loud: why do leaves let go in fall? Wondering together is the lesson."},{"t":"Tree Book Snuggle","d":"Read a fall or tree book together tonight, then add the Bear Phonics reader “See Me Eat Meat.” Pointing to the words as you read shows your child how reading works."}]},{"day":"Friday","focus":"Rake and Share","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Family Yard Team","d":"Give your child a small rake or dustpan and tidy the yard or porch together, taking turns with the tools. Working alongside you is how threes learn to pitch in."},{"t":"Taking Turns Toss","d":"Take turns tossing leaves into a bucket — your turn, my turn — counting to three between throws. Waiting a turn is hard work at three; games make it easier."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Fall is one big free classroom — step outside and it's all there.","items":["Trace the letter T on your child's back and let them guess it — then swap.","Collect three leaves on every walk this week and count them into a jar.","Triangles hide in trees — point out how pines make a triangle shape.","Read together under a blanket tent — the coziest reading spot of fall."]}},{"label":"Week 2 — Bugs & Critters","days":[{"day":"Monday","focus":"Move Like Bugs","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Bug Moves Game","d":"Call out bugs and move like them — crawl like a beetle, flutter like a butterfly, jump like a cricket. J is for jump — say the sound on every hop."},{"t":"Tape Web Crossing","d":"Zigzag masking tape across a hallway like a spider web and let your child climb through without touching. Wiggling over and under builds body control and giggles."}]},{"day":"Tuesday","focus":"A Bug Has","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Bug Watch Close","d":"Find a bug on the sidewalk or a window and watch it together without touching. Name what you see out loud — legs, wings, feelers — and let your child describe how it moves."},{"t":"Jump for J","d":"Say pairs of words — jump, bug, jar, leaf — and have your child jump only for the J words. Listening for first sounds is reading's first step."}]},{"day":"Wednesday","focus":"Bug Leg Math","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Six Legs Count","d":"Draw a bug body and let your child add six legs, counting each one, then three spots on its back. October's number three sneaks right into the art."},{"t":"Pasta Bug Sort","d":"Give your child a scoop of dry pasta “bugs” and sort them by shape into muffin-tin nests. Sorting and counting little critters is preschool math at its finest."}]},{"day":"Thursday","focus":"Gentle and Kind","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Gentle Critter Rules","d":"Make two family rules for meeting critters: look with your eyes, touch only with permission. Practicing gentleness with small creatures grows gentleness everywhere."},{"t":"Bug Rescue Hero","d":"If a bug wanders inside, scoop it with a cup and paper together and set it free outside. Being kind to the smallest things makes kids feel wonderfully big."}]},{"day":"Friday","focus":"Build a Bug","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Egg Carton Caterpillar","d":"Cut a strip from an egg carton and let your child color it and add paper antennae. Name the parts as you build — head, body, legs — craft and science in one critter."},{"t":"Sock Worm Puppet","d":"Slide a sock over your child's hand and let the “worm” wiggle, munch pretend leaves, and tell you about its day. Puppet talk pulls language out of even the quietest threes."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Little critters, big lessons — kindness and curiosity in the same tiny package.","items":["Jump like crickets while practicing the J sound — jump, jiggle, June bug.","Read a bug book together, then look for one real bug on your next walk.","Practice the outside rule: look first, then one gentle finger, only with permission.","Build a triangle bug house from three sticks on the porch and check it each morning."]}},{"label":"Week 3 — Weather & Sky","days":[{"day":"Monday","focus":"Weather Dance","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Weather Freeze Dance","d":"Dance like weather — spin like wind, patter like rain, stretch tall like sunshine — and freeze when the music stops. Ask “what weather are you?” at each freeze."},{"t":"Rain Sound Makers","d":"Pat thighs softly for drizzle, clap for rain, stomp for thunder — build a storm together, then calm it back down to quiet. A whole weather show, no props needed."}]},{"day":"Tuesday","focus":"Weather Words","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Window Weather Report","d":"Look out the window each morning and let your child give the weather report like a TV star: sunny, cloudy, windy, rainy. New describing words every single day."},{"t":"G for Gusty","d":"On a breezy day, step outside and feel the wind, then listen for the G sound: gusty, gray, go. Let your child pick the G word that fits the sky best."}]},{"day":"Wednesday","focus":"Chart the Sky","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Weather Week Graph","d":"Draw sun, cloud, and rain columns on paper and add an X for each day's weather. At week's end, count the columns together — which weather won?"},{"t":"Rain Cup Catcher","d":"Set a clear cup outside before rain and check it after: how much did the sky pour? Mark the water line with a crayon — real measuring, straight from the clouds."}]},{"day":"Thursday","focus":"Dress for Weather","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Dress the Weather","d":"Call out a weather — rainy, chilly, sunny — and let your child grab the right gear: boots, jacket, sun hat. Dressing for the day is a life skill in dress-up clothing."},{"t":"Who Works Outside","d":"Talk about people who work in all weather — mail carriers, builders, farmers — and wave a thank you when you spot one. Weather connects your child to the wider world."}]},{"day":"Friday","focus":"Sky Art","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Cloud Shape Watching","d":"Spread a blanket, lie back, and find shapes in the clouds together — a dog, a boat, a dinosaur. Then come inside and draw your favorite. Imagination plus observation equals magic."},{"t":"Night Sky Peek","d":"Just before bed, peek at the night sky together and count three stars or find the moon. A quiet look up is a calm end to a big day."}]}],"homeden":{"title":"The Home Den — This Week","lead":"The sky puts on a new show every day — this week, we watch it together.","items":["Let your child give the weather report at breakfast all week — your house meteorologist.","Practice G words in the mirror: go, gray, gust, giggle.","Read a bedtime book by flashlight one night — cozy reading is still reading.","Puddle rule for the week: boots on, grown-up right there, then splash away."]}},{"label":"Week 4 — Animals & Homes","days":[{"day":"Monday","focus":"Animal Walks","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Animal Walk Relay","d":"Hop like a bunny to the couch, waddle like a duck to the door, gallop like a horse back. Call the next animal before they finish — threes love the surprise."},{"t":"Guess My Animal","d":"Take turns acting out an animal with no words while the other person guesses. Acting and guessing both take patient thinking — and usually end in laughing."}]},{"day":"Tuesday","focus":"Animal Homes","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Who Lives Where","d":"Play a naming game: birds live in… nests. Bees live in… hives. Bears live in… dens — just like your family's den. Homes are your child's first idea of community."},{"t":"Home Sweet Homes","d":"Walk your street or look out the window and talk about the different homes you see — houses, apartments, tall and small. Everyone needs a cozy place; they just look different."}]},{"day":"Wednesday","focus":"Match and Count","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Animal Home Match","d":"Draw three animals and three homes on paper, cut them apart together, and let your child match each animal to its home. Matching is math; explaining why is science."},{"t":"Nest Egg Count","d":"Make three paper nests and deal out sock-ball eggs — can your child give each nest exactly three? Counting into groups is big thinking for little hands."}]},{"day":"Thursday","focus":"Kind to Animals","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Pet Care Practice","d":"Let your child help with a real pet job — filling the water bowl, gentle brushing — or give a stuffed pet a checkup and pretend dinner. Caring for animals grows empathy you can see."},{"t":"Animal Story Time","d":"Read an animal book tonight and ask “how does the animal feel?” on each page. Then finish with this month's Bear Phonics reader, “See Me Eat Meat.”"}]},{"day":"Friday","focus":"Build a Home","domains":["Creative Expression","Approaches to Learning"],"opts":[{"t":"Shoebox Animal Den","d":"Turn a shoebox into a den for a stuffed animal using blanket scraps and leaves from the yard. Ask what the animal needs — a bed? a door? — and let your child solve it."},{"t":"Big Blanket Burrow","d":"Build a people-sized burrow with blankets and chairs and crawl in like bears settling down for winter. Snuggle up with a flashlight for one last review: T, G, J — a whole outdoors month, done."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Every animal has a home — and yours has the coziest den of all.","items":["Review T, G, and J on cereal boxes and signs — three letters, three cheers.","Count in threes at snack: three crackers, three grapes cut small, three sips.","Play “which animal am I?” in the car — one clue at a time.","Read “See Me Eat Meat” once more and let your child chime in on the words they know."]}}]},"nov":{"theme":"Thankful Hearts","weeks":[{"label":"Week 1 — I Am Thankful","days":[{"day":"Monday","focus":"Thankful for People","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Thank-You Wave","d":"On a walk or from the window, wave and call 'thank you!' to the mail carrier or the trash truck. Talk about how helpers take care of our neighborhood. Gratitude starts with noticing people."},{"t":"Dinner Thank-Yous","d":"At dinner, help your child tell each person one 'thank you for…' — thank you for my hug, thank you for my snack. Hearing themselves say it makes kindness feel real."}]},{"day":"Tuesday","focus":"Count to Four","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Four Blessings Fingers","d":"Help your child name four things they love and count them on fingers — one gentle squeeze per finger. Four is our number this month, so cheer a little when you land on it."},{"t":"Thankful Tower","d":"Stack four blocks, cups, or cans, naming one happy thing per piece. If the tower tumbles, laugh and rebuild — trying again is the real lesson hiding inside."}]},{"day":"Wednesday","focus":"The H Sound","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"Huff Like H","d":"Show your child how H sounds like blowing warm air on cold hands — h-h-h. Then hop, hug, and hum together, stretching that /h/ at the start of each word."},{"t":"Tape Letter Walk","d":"Lay a giant H on the floor in masking tape and let your child walk it like a balance beam, arms out wide. Big-body letters stick in little memories."}]},{"day":"Thursday","focus":"Five Senses Thanks","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Thankful Senses Hunt","d":"Sit together in one cozy spot and hunt with senses instead of feet: name a sound you're glad for, a smell you love, something soft within reach. Noticing what feels good is gratitude a three-year-old can hold."},{"t":"Mystery Touch Bag","d":"Drop a spoon, a sock, and a leaf into a bag and let your child feel and guess without peeking. Talk about how our hands help us learn — one more thing to be thankful for."}]},{"day":"Friday","focus":"Thankful Tree","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Handprint Leaves","d":"Trace your child's hand on paper and cut out a few leaves — let them snip the easy edges with safety scissors while you steer. Write one thankful thing on each and grow a fridge-door thankful tree."},{"t":"Read and Snuggle","d":"End the week cozy with the Bear Phonics reader He Eats Meat, letting your child huff the /h/ in 'he.' Reading the same little book again and again is exactly how three-year-olds learn."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Little thankful moments, tucked right into your week.","items":["At bedtime, trade one good thing from the day — yours and theirs.","Spot yellow all week — yellow is our color of the month.","Trace a big H in flour, sand, or bath-time bubbles.","Count to four everywhere: stairs, crackers, buttons, hugs."]}},{"label":"Week 2 — Family & Home","days":[{"day":"Monday","focus":"My Family Story","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Photo Talk","d":"Scroll a few family photos together and let your child name each person and one thing that person loves. Talking about family builds belonging and full sentences at the same time."},{"t":"Draw My Family","d":"Hand over the crayons and ask for a family picture, then write their words underneath: 'This is Daddy. He is big.' Their drawing plus your writing is early literacy, for real."}]},{"day":"Tuesday","focus":"Big Helper Day","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Sock Match Helper","d":"Dump the clean socks and let your child find the pairs and roll them into balls. Matching is early math, and finishing a real job start to end feels wonderful at three."},{"t":"Carry with Care","d":"Give your child a real chore: carry the napkins and set one at each place, walking slowly with two hands. Real work builds strong bodies and proud hearts."}]},{"day":"Wednesday","focus":"Count My Family","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Family Finger Count","d":"Count everyone in your family on fingers — pets absolutely count. Then ask, 'How many people live in our home?' and count again to check. Counting the people they love makes numbers matter."},{"t":"Shoe Lineup","d":"Line up everyone's shoes by the door, count them, and sort out whose is whose. Big shoes, little shoes — comparing sizes is math talk too."}]},{"day":"Thursday","focus":"Homes Keep Us Safe","domains":["Scientific Inquiry","Creative Expression"],"opts":[{"t":"Blanket Fort Reading","d":"Build a blanket fort, climb in with a flashlight, and read a story together inside your cozy pretend home. Talk about how real homes keep us warm, dry, and safe."},{"t":"Box House Build","d":"Turn a cardboard box into a house for a stuffed animal, cutting a rectangle door together — rectangle is our shape this month. Ask what the animal needs to feel safe and snug inside."}]},{"day":"Friday","focus":"The K Sound","domains":["Language & Literacy","Physical Development"],"opts":[{"t":"K is for Kick","d":"Say a K word — kick, kitchen, kangaroo — then let your child kick a soft ball across the room. That little /k/ pops at the back of the throat; make it silly and loud."},{"t":"Kitchen K Look","d":"Walk the kitchen together spotting K things: kettle, ketchup, keys. Tape a paper K on each one you find, then count your Ks at the end."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Family is the theme — keep it close all week.","items":["Let your child own one real chore this week, like napkin duty.","Name who is in your family at dinner — grandmas and pets count.","Look for rectangles around the house: doors, windows, phones.","Practice the /k/ sound with a goodnight kiss — k-k-kiss."]}},{"label":"Week 3 — Sharing & Giving","days":[{"day":"Monday","focus":"Please and Thanks","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Magic Words Play","d":"Play tea party or grocery store and sprinkle in 'please' and 'thank you' every time something is passed. Pretend play is where manners get their practice reps."},{"t":"Puppet Manners","d":"Slip a sock on your hand and let the puppet 'forget' its manners — your child gets to teach it what to say. Being the teacher makes the lesson stick."}]},{"day":"Tuesday","focus":"Fair Shares","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Pour It Fair","d":"Set out two clear cups and pour water until both sides look the same — kneel down and check at eye level, and stay within arm's reach. Same or different, more or less? That's real measuring."},{"t":"Snack Server","d":"Let your child be the snack server: one cracker for you, one for me, until everyone has four. Passing out fair shares is early division with a please and thank you on top."}]},{"day":"Wednesday","focus":"Pass It Along","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Pass the Beanbag","d":"Roll socks into a ball and pass it around the family circle to music; when the music stops, whoever holds it says something kind. Waiting for the pass is turn-taking in action."},{"t":"Deliver the Goods","d":"Set up a delivery game: your child carries a 'package' (a pillow) across the room, around a chair, and into your waiting hands. Add one more step each round and watch them concentrate."}]},{"day":"Thursday","focus":"Helping Feels Good","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Helper for a Day","d":"Pick one way to help someone else today — feed the pet, water a plant, hold the door. Afterward ask, 'How did that feel inside?' Naming the warm feeling helps it grow."},{"t":"Giveaway Basket","d":"Fill a small basket with gently loved toys to pass along to another family. Let your child do the choosing — it's their giving, and choosing makes it real."}]},{"day":"Friday","focus":"Thank-You Cards","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Card for a Helper","d":"Fold paper into a card and decorate it for someone who helps your child — a teacher, a grandparent, the crossing guard. Write their dictated words inside and deliver it together."},{"t":"Love Letter L","d":"Draw a big L on the front of a card — L says /l/ like la-la-la. Fill the inside with things your child la-la-loves, then read your list together at bedtime."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Sharing gets easier with practice — here's the practice.","items":["Practice trades: 'When you're done, may I have a turn?'","Catch them being kind and say exactly what you saw.","Find four yellow things and line them up smallest to biggest.","Sing la-la-la for letter L in the car — long, lazy, loud."]}},{"label":"Week 4 — A Thankful Feast","days":[{"day":"Monday","focus":"Set the Table","domains":["Physical Development","Social Studies"],"opts":[{"t":"Table Captain","d":"Make your child the table captain tonight: napkin, cup, and fork at every place, carried slowly with two hands. Family jobs done with care build steady hands and proud helpers."},{"t":"Follow the Setting","d":"Draw a simple place setting on a paper 'map' — circle for the plate, fork on the left — and let your child match the real pieces on top. Following a plan is a skill they'll use everywhere."}]},{"day":"Tuesday","focus":"Harvest Food Talk","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"H Food Feast","d":"Name foods with the /h/ sound — ham, honey, hash browns — and huff the H at the start of each. Then pick one and talk about its journey from farm to table."},{"t":"Where Food Grows","d":"At dinner, pick one food on the plate and trace its story: a carrot grew in dirt, bread began as wheat. Wondering where things come from is a scientist's first habit."}]},{"day":"Wednesday","focus":"Count the Feast","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Plates and Cups","d":"Before dinner, ask: 'How many plates do we need? How many cups?' Count them out together, then double-check by matching one to each chair. Counting with a purpose is the best kind."},{"t":"Rectangle Placemats","d":"Cut paper placemats together — rectangles, our shape this month — and count the four sides and four corners on each. Snip, count, set the table, feast."}]},{"day":"Thursday","focus":"Gratitude Circle","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Family Gratitude Circle","d":"Hold hands around the table and take turns: 'I am thankful for…' Little ones can copy yours word for word — that's how it starts. End with a squeeze passed around the circle."},{"t":"Record a Thank-You","d":"Record a short video of your child saying thank you to someone far away — a grandparent will play it a hundred times. Saying it out loud, for real ears, makes gratitude concrete."}]},{"day":"Friday","focus":"Feast and Celebrate","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Paper-Plate Harvest","d":"Turn a paper plate into a harvest wreath: tear or snip bits of yellow, orange, and brown paper and glue them around the rim. Tearing and snipping are finger workouts in disguise."},{"t":"Story Feast","d":"Set up a cozy 'story feast': a blanket, a snack, and a stack of books — including He Eats Meat, which your child may nearly know by heart now. Let them 'read' it to you this time."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A feast week — gather, count, and say thank you together.","items":["Let your child hand out one thing at dinner every night this week.","Play 'guess the food' with eyes closed — smell first, then taste.","Trace H, K, and L, then spot each letter on cereal boxes.","Say one thank-you to a new person each day — count to four by Friday."]}}]},"dec":{"theme":"Lights & Traditions Around the World","weeks":[{"label":"Week 1 — Lights Around the World","days":[{"day":"Monday","focus":"Glow and Shine","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Light Word Collection","d":"Turn off the lights, click on a flashlight, and collect light words together: glow, shine, bright, twinkle, sparkle. New words stick best when there's a little magic attached."},{"t":"What Glows?","d":"Walk the house asking, 'Does this glow?' — lamp yes, spoon no, night-light yes. Sorting glow from no-glow is a three-year-old's version of a real experiment."}]},{"day":"Tuesday","focus":"Twinkle and Freeze","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Twinkle Freeze Dance","d":"Play music and dance with wiggly 'twinkle fingers'; when the music stops, freeze like a statue. Stopping a moving body on cue is self-control practice in disguise."},{"t":"Flashlight Follow","d":"Shine a flashlight dot on the wall and floor and let your child chase it, hop on it, or tiptoe after it. You set the speed — slow for calm, quick for giggles."}]},{"day":"Wednesday","focus":"Count the Lights","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Evening Light Walk","d":"Take a short after-dinner walk and count lights — porch lights, windows, five twinkly ones in a row. Five is our number this month, so make it the star of the count."},{"t":"Light Pattern Line","d":"Line up blocks or cups in an on-off-on-off pattern and 'read' it aloud together. Then let your child continue it. Copying and growing patterns is real pre-math thinking."}]},{"day":"Thursday","focus":"Cozy and Bright","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Candle-Glow Talk","d":"Dim the lights, switch on one small lamp or battery tea-light, and snuggle close. Talk about how people all over the world light candles and lamps when they celebrate — light means warm, safe, together."},{"t":"Cozy Corner Build","d":"Build a little cozy corner with a blanket and pillow where your child can go to feel calm. Ask, 'What makes you feel warm and safe?' and listen to every answer."}]},{"day":"Friday","focus":"Star Makers","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Paper Star Craft","d":"Cut a big star together — star is our shape this month — letting your child snip the straight edges with safety scissors while you steer. Hang it in the window and let them announce it to everyone."},{"t":"Flashlight Story Time","d":"Read a bedtime story by flashlight, letting your child hold the light. This month's Bear Phonics reader We See Feet makes a great flashlight book — spot the letter W as you read."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A little light goes a long way this week.","items":["Say goodnight to the moon and stars from the window.","Whisper the /w/ sound — wuh — for wiggle, window, warm.","Count five of anything each day: buttons, grapes, kisses.","Spot stars everywhere — on signs, pajamas, and in the sky."]}},{"label":"Week 2 — Family Traditions","days":[{"day":"Monday","focus":"My Family Does","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Tradition Show-and-Tell","d":"Ask your child to finish 'My family always…' — taco night, Sunday pancakes, a special song. Write their answer down and read it back; their own words on paper is powerful stuff."},{"t":"Grandparent Story Call","d":"Call a grandparent or old friend and ask, 'What did you celebrate when you were little?' Your child hears that traditions come from somewhere — and that people love to tell them."}]},{"day":"Tuesday","focus":"Dance It Out","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Family Dance Party","d":"Put on music your family loves — from any culture, any decade — and teach your child one simple move to it. Dancing the way your family dances is a tradition all by itself."},{"t":"Scarf Twirl","d":"Hand over a scarf or dish towel and let it swoop, twirl, and float to the music. Big arm circles build the shoulder strength that handwriting needs later."}]},{"day":"Wednesday","focus":"Sort and Count","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Celebration Sort","d":"Gather celebration odds and ends — cards, candles, decorations — and sort them into groups your child chooses. Then count each pile and find the pile of five."},{"t":"Napkin Fold Count","d":"Fold five napkins for dinner together, counting each one into a stack. Folding cloth and paper is trickier than it looks — watch those little hands concentrate."}]},{"day":"Thursday","focus":"Foods and Smells","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Smell Memory Game","d":"Let your child sniff three kitchen smells with eyes closed — cinnamon, orange peel, cocoa — and guess each one. Smell is the sense most tied to memory; you're building cozy ones right now."},{"t":"Cook One Together","d":"Pick one simple family food and give your child a real job: stirring, sprinkling, mashing. Talk about who taught you to make it. Kitchens are where traditions get handed down."}]},{"day":"Friday","focus":"The F Sound","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Finding F","d":"Feel the /f/ sound — top teeth on bottom lip, fff — then walk the house spotting F things: fork, fan, fuzzy blanket. Sounds stick fastest when they're attached to things little hands can grab."},{"t":"Tradition Collage","d":"Make a family-tradition collage from old photos, magazine scraps, or your child's drawings. Let them decide what goes where — then hang it low enough for them to visit."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Your family's ways are worth celebrating — share them out loud.","items":["Tell one story from your own childhood at bedtime.","Read a book together about a celebration different from your own.","Find the letter F on boxes and signs — fff every time.","Let your child help make one family food this week."]}},{"label":"Week 3 — Giving & Kindness","days":[{"day":"Monday","focus":"Kind Words","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Kind Words Jar","d":"Start a kind-words jar: every time someone in the house says something kind, drop in a piece of dry pasta. Retell the day's kind words at dinner — kindness grows when it's noticed."},{"t":"Compliment Mirror","d":"Stand at the mirror together and trade compliments — 'You have a great laugh.' 'You are a good helper.' Hearing kind words about themselves teaches them to hand kindness out."}]},{"day":"Tuesday","focus":"Delivery Duty","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Gift Delivery Relay","d":"Wrap a small 'gift' (any toy in a dish towel) and set up a delivery route: over the pillow, around the chair, into waiting hands. Careful carrying plus a finish line equals joyful concentration."},{"t":"Secret Kindness Mission","d":"Give your child a secret mission: sneak a drawing under someone's pillow without being seen. Tiptoeing, planning, holding the secret — it's all self-control with a sweet payoff."}]},{"day":"Wednesday","focus":"Count and Give","domains":["Mathematical Thinking","Social Studies"],"opts":[{"t":"Five to Give","d":"Choose five things to give away together — toys, books, mittens — counting as you go. Talk about the people who will get them. Giving is bigger when little hands do the choosing."},{"t":"Count the Cans","d":"If you're gathering food to share, let your child count the cans into the bag — aim for five. Heavy lifting plus counting plus helping a neighbor: that's a full morning of learning in one bag."}]},{"day":"Thursday","focus":"Warm Heart Check","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Heartbeat Hello","d":"Have your child hop ten times, then feel their own heartbeat — thump thump! Later, after doing something kind and quiet, 'check' the heart again. Noticing how bodies feel builds body awareness."},{"t":"Warm Heart Chat","d":"After your child gives or helps, get down to eye level and ask: 'How does your heart feel right now?' Warm, fizzy, happy — any word works. Noticing the feeling is what makes givers."}]},{"day":"Friday","focus":"The N Sound","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"N is for Nice","d":"Trace a big N and hum its sound — nnn, like a tiny motor behind your nose. Then list nice N things together: nest, nose, night, noodles. Silly lists make sounds stick."},{"t":"Make-a-Gift Art","d":"Make a gift for someone: a painted rock, a paper star, a drawing rolled up and tied with yarn. Made-by-me gifts teach that giving comes from hands and hearts, not stores."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Kindness is the tradition this week — practice it everywhere.","items":["Read We See Feet together and wiggle your feet at every 'feet.'","Do one secret kindness a day and whisper about it at bedtime.","Count out five crackers to share with someone at snack.","Spot green everywhere this week — green is our color of the month."]}},{"label":"Week 4 — Celebrations","days":[{"day":"Monday","focus":"Parade Time","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Pots-and-Pans Parade","d":"Hand out a pot, a wooden spoon, and a proud marching order: parade through the whole house. March with high knees, then tiptoe, then slow motion. A parade is gross-motor work with confetti on top."},{"t":"Ribbon Wand March","d":"Tape ribbon or yarn to a spoon and march while it swirls. Call out 'high, low, fast, slooow' — then let your child be the leader on the second lap."}]},{"day":"Tuesday","focus":"Tell the Story","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Retell a Celebration","d":"Look at photos of a past celebration and let your child tell you the story: who came, what you ate, what happened first and next. Retelling in order is a real pre-reading skill."},{"t":"World of Celebrations","d":"Talk about how children everywhere celebrate — with lights, songs, special foods, and family. Then ask, 'What do WE do?' Belonging to a big wide world starts with noticing it."}]},{"day":"Wednesday","focus":"Count Down Five","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Countdown Jumps","d":"Count down from five together — 5, 4, 3, 2, 1 — and leap in the air on 'celebrate!' Counting backward is harder than forward; jumping makes the practice irresistible."},{"t":"Paper Chain Days","d":"Make a paper chain of five links and tear one off each day, counting how many are left. Watching a number shrink teaches take-away long before anyone says 'subtraction.'"}]},{"day":"Thursday","focus":"Celebration Sounds","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Sound Shaker Test","d":"Drop rice or dry pasta into containers with tight lids and shake: which is loudest? Which is softest? Predict first, then test — that's the whole scientific method, kitchen edition."},{"t":"Joy Check-In","d":"Ask: 'What does excited feel like in your body?' Wiggly legs, jumpy tummy, big smile. Then practice one slow, deep breath for when excitement gets too big. Naming joy matters as much as naming mad."}]},{"day":"Friday","focus":"The O Sound","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"O Mouth Mirror","d":"Look in the mirror and say O — watch your mouths turn into little Os. Then walk the house calling O words: open, over, octopus. A letter you can see on your own face is unforgettable."},{"t":"Celebration Decorations","d":"Make decorations for a Friday family celebration: paper stars, green paper chains, a big O garland. Then celebrate — dinner is fancy tonight simply because you're together."}]}],"homeden":{"title":"The Home Den — This Week","lead":"End the year celebrating the littlest, best things.","items":["Count down to anything — bath, dinner, lights out — from five.","Trace W, F, N, and O with a finger on a foggy window.","Find stars on pajamas, signs, and up in the night sky.","Say one thing you loved about today, every night this week."]}}]},"jan":{"theme":"Winter Wonders","weeks":[{"label":"Week 1 — Snow & Ice","days":[{"day":"Monday","focus":"Ice Explorers","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Melting Ice Watch","d":"Set one ice cube on a plate in the sun and one in the fridge, then check back: which melts first? Predict, watch, and talk about cold and warm — a real experiment with zero cleanup."},{"t":"Cold Word Collection","d":"Collect cold words together — ice, frost, chilly, freezing, brrr — and say each one in your best shivery voice. Then open the freezer for one quick 'winter wind.' New words plus giggles stick."}]},{"day":"Tuesday","focus":"Skate and Freeze","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Sock Skating Rink","d":"Slide in socks across a smooth floor like an ice skater — long, slow glides with arms out for balance, with you close by. Balance and big careful movements are the day's real work."},{"t":"Frozen Statues","d":"Play 'freeze like ice': dance, then freeze solid when you call 'FREEZE!' Hold still, still, still — then 'melt' slowly down to the floor. Stopping and holding is self-control practice."}]},{"day":"Wednesday","focus":"Snowball Counting","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Six Snowball Toss","d":"Roll six 'snowballs' from socks or crumpled paper and toss them into a laundry basket, counting every throw. Six is our number this month — count the hits and the misses both."},{"t":"Snowball Size Sort","d":"Crumple paper snowballs in three sizes and sort them big, medium, small — then count six into a bowl. Sorting and counting the same pile twice is double the math."}]},{"day":"Thursday","focus":"Cozy Warm Feelings","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Snowy Places Talk","d":"Look at pictures of snowy places and children all bundled up. Talk about how families in cold places stay warm — big coats, cozy fires, warm drinks. The world is big, and children live all over it."},{"t":"Calm Like Snow","d":"Make pretend snow fall — flutter your fingers down slowly from up high — then float down to lie on the floor, quiet and calm. It's a calm-down trick disguised as winter play."}]},{"day":"Friday","focus":"The D Sound","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"D Drum Day","d":"Tap a big /d/ on an upside-down pot — d, d, d — for drum, dance, dinosaur. Then read this month's Bear Phonics book Feed Me together and drum one beat every time you hear a D."},{"t":"Cotton-Ball Snowman","d":"Glue cotton balls or torn paper into a snowman on blue paper, then add a paper hat and a carrot nose. Let your child name him — sticky fingers, strong imaginations."}]}],"homeden":{"title":"The Home Den — This Week","lead":"No snow needed — winter wonder works just fine in a warm state.","items":["Freeze a small toy in a cup of ice and rescue it together at the sink.","Say the /d/ sound at every door — d-d-door, all week.","Count to six on fingers: five and one more.","Spot blue everywhere — blue is our color of the month."]}},{"label":"Week 2 — Winter Animals","days":[{"day":"Monday","focus":"Move Like Animals","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Waddle, Stomp, Sneak","d":"Waddle like a penguin, stomp like a bear, sneak like a fox — call out the animal and let your child become it. Ask, 'Why do you think penguins waddle?' Wondering counts as science."},{"t":"Hibernation Den","d":"Drape a blanket over two chairs and hibernate like bears: crawl in, curl up, snore dramatically, then 'wake up' in spring. Talk about why bears sleep through the winter."}]},{"day":"Tuesday","focus":"Animal Winter Plans","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Sleep, Fly, or Stay","d":"Make a simple three-spot chart — sleeps, flies away, stays and grows fluff — and place animal toys or drawings in each. Big words like 'hibernate' and 'migrate' are candy to three-year-olds."},{"t":"Animal Sound Guess","d":"Play the guessing game: 'I waddle and I love to swim in cold water — who am I?' Then trade, and let your child give the clues. Making up clues is thinking turned inside out."}]},{"day":"Wednesday","focus":"Count the Animals","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Six Animal Parade","d":"Line up six stuffed animals for a winter parade and count them nose to tail. Then count again walking back down the line — still six! Discovering the count stays the same is huge."},{"t":"Animal Jump Count","d":"Call an animal and a number: 'Penguin, hop six times. Bear, stomp four.' Counting with the whole body helps wiggly learners lock numbers in."}]},{"day":"Thursday","focus":"Gentle and Caring","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Bird Watch Care","d":"Watch for birds and squirrels out the window and talk about how neighbors help animals in winter — feeders, fresh water, gentle hands. Caring for small things grows kind big people."},{"t":"Pet Vet Pretend","d":"Set up a pretend animal clinic: stuffed animals get gentle check-ups, warm blankets, and quiet voices. Pretend caring is real practice for the real thing."}]},{"day":"Friday","focus":"Penguin P Day","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"P Pop Practice","d":"Pop the /p/ sound — p, p, penguin — and feel the little puff of air on your hand. Then march the room listing P words: penguin, polar, paw, pounce."},{"t":"Handprint Penguin","d":"Paint or trace your child's hand to make a handprint penguin on blue paper, then add paper-dot eyes. Name the penguin and write its story together: 'This is Pip. Pip likes fish.'"}]}],"homeden":{"title":"The Home Den — This Week","lead":"A week of waddling, wondering, and warm little hearts.","items":["Read an animal book together and guess what each one does in winter.","Waddle like a penguin from the bath to bed — pajama-time fun.","Practice the /p/ puff on your palm: p-p-penguin.","Count six animal crackers or toy animals before they disappear."]}},{"label":"Week 3 — Staying Warm & Cozy","days":[{"day":"Monday","focus":"Dress for Winter","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Dress-Up Relay","d":"Pile up a big shirt, a hat, and socks, and race the clock: how fast can your child get 'winter ready'? Zippers, buttons, and pull-on sleeves are fine-motor gold."},{"t":"What Goes First","d":"Lay out clothes and ask, 'What goes on first — shoes or socks?' Let them test the silly way once, boots before pants. Sequencing gets learned fastest through giggles."}]},{"day":"Tuesday","focus":"Warm Clothes Science","domains":["Language & Literacy","Scientific Inquiry"],"opts":[{"t":"Warm Clothes Words","d":"Name winter clothes as you touch them — coat, mittens, scarf, boots — and find the D words: down, dry. Then ask the big question together: how does a coat keep us warm?"},{"t":"Warm Hands Test","d":"Have your child hold one hand bare and tuck the other inside a sock for a minute, then compare: which feels warmer? A one-minute experiment that answers 'why do I need a jacket?' forever."}]},{"day":"Wednesday","focus":"Mitten Math","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Mitten Pair-Up","d":"Scatter socks and mittens around the room and match the pairs — then run each pair to the 'mitten basket.' The matching is math; the running is just joy."},{"t":"Diamond Mitten Line","d":"Cut paper mittens, decorate them with diamond shapes — our shape this month — and hang six on a string with clothespins. Pinching clothespins builds the muscles handwriting needs."}]},{"day":"Thursday","focus":"Cozy Calm Down","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Cozy Nest Time","d":"Make a cozy nest of blankets and practice 'cozy breathing' — slow breath in, warm breath out onto cold hands. A calm-down spot they helped build is one they'll actually use."},{"t":"Warm Coats for Others","d":"Sort outgrown coats and warm clothes together to pass along to another family. Talk about how neighbors keep each other warm. Little givers grow from real giving jobs."}]},{"day":"Friday","focus":"The Q Sound","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Quiet Q Time","d":"Q says /kw/ — quack, quiet, quilt. Practice a duck's loudest QUACK, then its quietest whisper-quack. Then read Feed Me together in your best quiet, cozy voices."},{"t":"Design a Mitten","d":"Draw a giant mitten and let your child design it: stripes, dots, diamonds, all the blue they want. Tape it to the fridge and design its matching partner tomorrow."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Warm hands, warm hearts — that's the whole week.","items":["Let your child zip, button, and buckle for themselves — slow is fine.","Whisper-quack the letter Q at bath time: qu-qu-quack.","Find diamond shapes on kites, playing cards, and crackers.","Practice cozy breathing before bed: smell the cocoa, cool the cocoa."]}},{"label":"Week 4 — Winter Fun","days":[{"day":"Monday","focus":"Indoor Snowballs","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Snowball Toss Game","d":"Crumple paper 'snowballs' and take turns tossing them into a basket, a box, and a big bowl — three targets, six throws each. Taking turns when it's this fun is the hardest, best practice."},{"t":"Snowball Sweep Race","d":"Sweep paper snowballs across the floor to a finish line using a cardboard tube or a toy broom. Pushing and steering builds the shoulders and focus of a future writer."}]},{"day":"Tuesday","focus":"Winter Play Stories","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Snowy Day Dreams","d":"Talk about how children in snowy places play — sledding, snow angels, building snowmen — and ask what your child would build. Warm-state kids can dream in snow too; imagining is the point."},{"t":"First, Next, Last","d":"After any game today, help your child tell it back: 'First we crumpled, next we tossed, last we cheered!' Retelling in order is the same muscle they'll use to retell stories."}]},{"day":"Wednesday","focus":"Graph Our Favorites","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Family Favorites Graph","d":"Vote on your favorite winter game — snowball toss, freeze dance, fort building — and stack one block per vote to build a tower graph. Whose is tallest? Voting plus counting equals graphing."},{"t":"Six-Jump Contest","d":"Make a tape line on the floor and jump from it six times, marking where each jump lands. Which jump went farthest? Comparing distances is measurement without a ruler."}]},{"day":"Thursday","focus":"See Your Breath","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Breath Cloud Wonder","d":"Huff slowly on a cold mirror or window and watch it fog up, then draw a tiny picture in the mist. Why does that happen? Warm breath meets cold — wondering out loud together is the lesson."},{"t":"Snowflake Breathing","d":"Hold a scrap of tissue up high and blow it like a drifting snowflake — slow breaths float it, fast breaths fly it. Breath control calms big feelings; this is practice dressed as play."}]},{"day":"Friday","focus":"Snowflake Finale","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Snowflake Painting","d":"Paint snowflakes on blue paper with white paint and cotton swabs — dots, lines, sparkly diamonds. Every real snowflake is different; every painted one gets to be too."},{"t":"Winter Wonders Recap","d":"Snuggle up and read Feed Me one more time, then ask: 'What was your favorite winter wonder this month?' Write their answer on the back page with the date — a tiny time capsule."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Wrap up winter with play, giggles, and one proud look back.","items":["Play one round of indoor snowball toss before dinner.","Trace D, P, and Q on a foggy mirror after bath time.","Count six jumps, six claps, six kisses goodnight.","Ask 'what was your favorite part today?' every night this week."]}}]},"feb":{"theme":"Kindness & Friendship","weeks":[{"label":"Week 1 — What Is a Friend?","days":[{"day":"Monday","focus":"What Makes a Friend","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Friend Talk","d":"At snack, ask your child, 'What makes someone a good friend?' Write their answer on paper and read it back to them. Hearing their own words read aloud shows a three-year-old that their ideas matter."},{"t":"Teddy Bear Meet-Up","d":"Line up stuffed animals and help your child introduce them to each other — a name, a wave, a 'nice to meet you.' Practicing greetings on teddies makes greeting real friends feel easy."}]},{"day":"Tuesday","focus":"Mirror a Friend","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Copycat Moves","d":"Stand face to face and move slowly — arms up, wiggle, tiptoe — while your child mirrors you. Then swap so they lead. Watching and copying builds focus and body control at the same time."},{"t":"Living Room Parade","d":"Play follow-the-leader through the house: march, hop, crawl under the table. Take turns being the leader. Leading and following are both friendship skills in disguise."}]},{"day":"Wednesday","focus":"Alike & Different","domains":["Social Studies","Scientific Inquiry"],"opts":[{"t":"Mirror Together","d":"Stand at the mirror side by side and notice things out loud: 'We both have brown eyes. Your hair is curly, mine is straight.' Noticing alike-and-different is how children learn every person is one of a kind."},{"t":"Family Sock Study","d":"Pull socks from the laundry and compare — big, small, striped, plain. Whose are alike? Whose are different? Sorting real family things turns observation into a game."}]},{"day":"Thursday","focus":"Count Our Friends","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Love Count","d":"Name the people who love your child — family, friends, teachers — and count them on fingers as you go. Aim past seven, this month's number. Counting people they love makes numbers feel warm."},{"t":"Seven Paper Hearts","d":"Cut or tear seven paper hearts together and count them out loud, one to seven. Hide them around the room and count again as your child finds each one."}]},{"day":"Friday","focus":"Friendship Portraits","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Draw a Friend","d":"Ask your child to draw a friend they like, then tell you about the picture while you write their words underneath. At three, telling the story of a drawing is early writing."},{"t":"Rrr Reading Time","d":"Practice this month's letter R — 'rrr' like a friendly lion — then snuggle up and read together. Bear Phonics fans can read The Deer Sees Seeds. Ending the week with a book and a lap is friendship too."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these into your week — little friendship lessons hiding in plain sight.","items":["Ask 'Who did you play with today?' at pickup or dinner — one small question keeps friends on their mind.","Point out the letter R on signs and cereal boxes — 'rrr' like a friendly lion.","Count to seven on fingers at bath time — seven is February's number.","Draw a heart — this month's shape — on a napkin and slip it into lunch."]}},{"label":"Week 2 — Kind Words & Deeds","days":[{"day":"Monday","focus":"R Is for Respect","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Rrr Respect Words","d":"Practice the 'rrr' sound together, then talk about respect in three-year-old words: gentle hands, listening ears, waiting your turn. Big word, small examples — that's how character sticks."},{"t":"Kind Words Telephone","d":"Whisper a kind message in your child's ear — 'you are a great helper' — and let them carry it across the room to deliver to someone else. Kind words travel; practicing the delivery makes them easier to say."}]},{"day":"Tuesday","focus":"Kindness Delivery","domains":["Physical Development","Social Studies"],"opts":[{"t":"Kindness Relay","d":"Give your child small deliveries around the house — a cup of water for Grandma, slippers for Dad — and cheer each drop-off. Running kind errands builds strong legs and a helper's heart."},{"t":"Neighbor Surprise","d":"Draw a cheerful picture together and, with you right there, leave it at a neighbor's door or mail it to a relative. Kindness that travels beyond home teaches that community is people we care for."}]},{"day":"Wednesday","focus":"Count Kind Acts","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Kindness Jar","d":"Set out a cup or jar and drop in one piece of dried pasta every time someone in the family does something kind. Count the pieces together each evening — can you reach seven?"},{"t":"Heart Tally Chart","d":"Tape paper to the fridge and draw a small pink heart each time your child uses kind words. Watching the row grow shows them kindness adds up."}]},{"day":"Thursday","focus":"Kindness Feels Good","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Warm Fuzzy Check","d":"After your child does something kind, pause and ask, 'How does your body feel?' Warm, smiley, bouncy? Noticing that kindness feels good inside is real science — observing and describing."},{"t":"Feelings Check-In","d":"At bedtime, each name one feeling from the day — happy, frustrated, proud — and where you felt it in your body. Mrs. Bear's book Your Feelings Matter is a sweet companion if you have it."}]},{"day":"Friday","focus":"Fill a Bucket","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Family Buckets","d":"Set out a cup for each family member and decorate them together. Drop in tiny notes or drawings when someone is kind — full buckets, full hearts."},{"t":"Spot the Kindness","d":"Read Have You Filled a Bucket Today? or any story you have, and point out the kind moments in the pictures together. Spotting kindness in stories helps children spot it in real life."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Kindness grows fastest when someone names it out loud.","items":["Narrate kindness when you see it: 'You shared your crackers — that was kind.'","Keep the kindness jar going all week and count the pasta pieces on Sunday.","Practice one gentle apology script: 'I'm sorry. Are you okay? Can I help?'","Trace the letter R with a finger on a foggy mirror or in flour on a tray."]}},{"label":"Week 3 — Working Together","days":[{"day":"Monday","focus":"U Is for Us","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Uh, U, Us","d":"Practice the letter U — 'uh' like up and us — then list things your family does together as 'us': eat, play, clean up, snuggle. Team words build team feelings."},{"t":"Read It Together","d":"Share a book where you each hold one side and your child turns the pages. Say, 'We read it together — that's teamwork.' Shared jobs, even tiny ones, teach cooperation."}]},{"day":"Tuesday","focus":"Team Tower","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Tower for Two","d":"Build one tower taking turns — you place a block, then your child does. Count each block as it lands and see if you can reach ten before it topples."},{"t":"Cup Stack Challenge","d":"Stack plastic or paper cups into a pyramid together, counting as you go. When it crashes, laugh and try again — sticking with a tricky job is the real lesson."}]},{"day":"Wednesday","focus":"Blanket Teamwork","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Blanket Parachute","d":"Hold a blanket between you, toss on a few rolled socks, and shake together to make them pop like popcorn. It only works when you both work — teamwork you can feel."},{"t":"Laundry Basket Haul","d":"Carry a full laundry basket together, one handle each, then fold side by side. Real jobs done as a team make three-year-olds feel big and needed."}]},{"day":"Thursday","focus":"Two Hands Help","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"One Hand, Two Hands","d":"Try picking up a big pillow with one hand, then two — then try carrying it together. Which way was easiest? Testing and comparing is little-kid science."},{"t":"Team Pour Test","d":"At the counter, try pouring water from a big bowl into cups — first alone, then with you steadying the bowl while they pour. Talk about what worked better and why."}]},{"day":"Friday","focus":"Group Mural","domains":["Creative Expression","Social Studies"],"opts":[{"t":"Family Mural","d":"Tape a big piece of paper — a flattened grocery bag works — to the table and let everyone add to one picture. Hang it up and admire what 'us' made together."},{"t":"Jobs People Do","d":"While you draw together, talk about people whose jobs take teamwork — firefighters, builders, teachers. Ask, 'What job would you like?' and add it to the mural."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This week is all about 'we' — little jobs are better with two.","items":["Give one real team job a day: set the table together, match socks, water a plant.","Say 'we did it' instead of 'good job' after teamwork — it names the together part.","Point out the letter U on signs and labels — 'uh' like up and us.","Count to ten while you tidy: can the toys be put away before you finish counting?"]}},{"label":"Week 4 — Hearts & Helpers","days":[{"day":"Monday","focus":"V Is for Valentine","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Vvv Valentine Sound","d":"Practice the letter V — 'vvv' like a little motor — and feel your lips buzz. Then collect V words together: valentine, van, vegetables. Letter sounds you can feel are letter sounds that stick."},{"t":"Homemade Valentines","d":"Fold paper, draw hearts, and let your child 'sign' their name however they can. Making cards for people they love turns scribbles into messages."}]},{"day":"Tuesday","focus":"Helper of the Day","domains":["Social Studies","Physical Development"],"opts":[{"t":"Big Helper Jobs","d":"Crown your child Helper of the Day: feeding the pet, carrying napkins, pushing the laundry basket. Real responsibilities tell a three-year-old, 'You matter here.'"},{"t":"Helpers All Around","d":"On a drive or walk, spot the helpers — mail carriers, crossing guards, cashiers — and wave or say thank you. Children learn community by meeting it."}]},{"day":"Wednesday","focus":"Heart Sort & Count","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Heart Cut & Count","d":"Draw hearts in two sizes, help your child cut them out with safety scissors while you stay close, and count each pile. Sorting big from small is math they can hold."},{"t":"Pink Heart Line-Up","d":"Color paper hearts pink and line them up from smallest to biggest. February's shape and color in one quiet activity — perfect for a wiggly afternoon reset."}]},{"day":"Thursday","focus":"Feel Your Heartbeat","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Jump and Thump","d":"Have your child press a hand to their chest and feel the quiet thump. Then do ten big jumps and feel again — it beats faster because the heart is a muscle that loves to move."},{"t":"Heartbeat Hug","d":"During a long, quiet hug, ask your child to listen for your heartbeat. Talk about how hearts pump all day and night, even while we sleep. Cozy science counts too."}]},{"day":"Friday","focus":"Thank You, Helpers","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"Thank-You Delivery","d":"Help your child say one thank-you out loud to someone who helps them — a teacher, a sibling, the mail carrier. Naming exactly what the person did makes gratitude specific and real."},{"t":"Deer Sees Seeds Finale","d":"End the month with The Deer Sees Seeds, letting your child chime in on words they know, then celebrate with a big 'I did it.' Rereading a familiar book builds confident readers."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A heart-shaped week — helpers, thank-yous, and lots of love.","items":["Let your child help make dinner one night — tearing lettuce and stirring the cold bowls, well away from the stove.","Trace the letter V and the number 7 with a finger on the table at breakfast.","Catch a family member being helpful and thank them out loud, together.","Cut a heart from folded paper and tape it to their door — pink if you have it."]}}]},"mar":{"theme":"Things That Grow","weeks":[{"label":"Week 1 — Seeds & Plants","days":[{"day":"Monday","focus":"Seed to Tree","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Grow Like a Seed","d":"Curl up small on the floor like a seed, then slowly sprout — roots stretch, stem rises, arms open into branches. Acting out how plants grow plants the idea deep."},{"t":"Wind and Rain Sway","d":"Stand tall as trees and sway in pretend wind, patter fingers as rain falls, then stretch toward the pretend sun. Talk about how trees drink rain through their roots."}]},{"day":"Tuesday","focus":"Plant a Seed","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Bean in a Window","d":"Tuck a dried bean into a wet paper towel inside a clear bag or jar and tape it to a window. Check it together every day — the waiting and watching is the whole lesson."},{"t":"Cup Garden","d":"Plant a few dried beans or seeds in a cup of dirt from the yard, water lightly, and set it in a sunny spot. Let your child be in charge of checking it each morning."}]},{"day":"Wednesday","focus":"Count & Sort Seeds","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Seed Count to Eight","d":"Count out eight dried beans — March's number is eight — moving one at a time into a cup. Moving objects while counting is how threes learn that numbers mean amounts. Stay close with small pieces."},{"t":"Big Seed, Little Seed","d":"Gather seeds from the kitchen — beans, popcorn kernels, rice — and sort them by size with pinching fingers. Sorting builds math brains and pencil-grip muscles at once. Supervise the little pieces."}]},{"day":"Thursday","focus":"I Is for I","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"I Can Grow","d":"Practice the long I sound — 'I,' like ice and I myself — then trade 'I can' sentences: 'I can jump. I can help.' Naming what they can do grows confidence like a seed."},{"t":"I Ride, I Slide","d":"Read this month's Bear Phonics book, I Ride, I Slide, and let your child point to the letter I on each page. Any favorite book works too — a lap and a story grow readers."}]},{"day":"Friday","focus":"Seed Collage","domains":["Creative Expression","Approaches to Learning"],"opts":[{"t":"Seed Art","d":"Spread glue on paper and press on dried beans, rice, or torn bits of paper to make a seed picture. Working slowly on a small design stretches focus and little fingers — stay close while the little pieces are out."},{"t":"Torn-Paper Garden","d":"Tear green and purple paper into stems and petals — purple is March's color — and glue a garden together. Tearing paper is scissor practice without the scissors."}]}],"homeden":{"title":"The Home Den — This Week","lead":"This month we grow things — starting with a seed and a little patience.","items":["Plant one seed in a cup on the windowsill and check it together each morning.","Say the long I sound in the mirror — 'I' — and watch your mouths make it.","Count to eight at the table: eight noodles, eight peas, eight crackers.","Point out purple, this month's color, everywhere — flowers, shirts, crayons."]}},{"label":"Week 2 — In the Garden","days":[{"day":"Monday","focus":"Pretend Garden","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Dig, Rake, Water","d":"Turn the living room into a pretend garden: dig with big arm scoops, rake, sprinkle pretend water, wipe your brow. Take the same moves outside if the weather is kind."},{"t":"Flower Shop Play","d":"Set up a flower shop with cups, spoons, and paper flowers, and take turns being gardener and customer. Pretend scripts like 'What would you like today?' grow real conversation skills."}]},{"day":"Tuesday","focus":"X Marks the Spot","domains":["Language & Literacy","Mathematical Thinking"],"opts":[{"t":"Hop to the X","d":"Tape a few big X's on the floor and call out moves — 'Hop to an X. Now tiptoe to another.' Say the letter's sound, 'ks,' like the end of box and fox."},{"t":"Treasure Map Garden","d":"Draw a simple map of one room, mark an X where a small treasure waits, and count the eight steps it takes to get there. Maps make math an adventure."}]},{"day":"Wednesday","focus":"Measure a Plant","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"How Tall Is It","d":"Measure a houseplant or your window bean with blocks or dried-pasta pieces stacked alongside: 'Four blocks tall.' Measuring with everyday objects is exactly how mathematicians start."},{"t":"Parts of a Plant","d":"Look closely at a real plant, flower, or backyard weed and name its parts — root, stem, leaf, flower. Let your child gently touch each part as you name it."}]},{"day":"Thursday","focus":"Where Food Grows","domains":["Social Studies","Approaches to Learning"],"opts":[{"t":"Kitchen Garden Tour","d":"Tour your kitchen and sort foods: 'Did this grow in the ground? On a tree?' Bananas, carrots, and rice all started as plants. Knowing where food comes from connects children to the farmers who grow it."},{"t":"Garden Book Time","d":"Read a growing story — The Tiny Seed, Planting a Rainbow, or any book with plants in it — and ask, 'What did it need to grow?' Stories water the week's big idea."}]},{"day":"Friday","focus":"Paper-Plate Flower","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Plate Bloom","d":"Color a paper plate, glue on torn-paper petals, and tape it to a window where you can both admire it. Say, 'You worked on that so patiently' — patience is this month's big word."},{"t":"Flowers for Someone","d":"Make a paper flower for someone your child loves and deliver it together. Making something slowly, on purpose, for someone else is patience with a heart."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A week in the garden — real or pretend, growing things grow patience.","items":["Give your child a daily plant job: check the seed, water gently, report the news.","Play I-spy for the letter X — it hides at the end of words like box and fox.","Measure something with pasta pieces or blocks and say the number together.","Ask at dinner: 'Which food on your plate grew from the ground?'"]}},{"label":"Week 3 — Baby Animals","days":[{"day":"Monday","focus":"Move Like Babies","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Baby Animal Moves","d":"Waddle like a duckling, hop like a bunny, wobble like a brand-new foal, curl like a kitten. Call out the animal and let your child invent the move — their version is the right one."},{"t":"Guess My Baby","d":"Take turns acting out a baby animal while the other guesses. No words allowed — just wiggles, hops, and peeps. Acting without talking builds body control and imagination."}]},{"day":"Tuesday","focus":"Z Is for Zebra","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Zzz Zebra Sound","d":"Buzz the letter Z together — 'zzz' like a sleepy bee — and feel it tickle your lips. Then collect Z words: zebra, zoo, zip, zigzag."},{"t":"Zigzag Stripes","d":"Draw a chunky zebra outline — a rectangle with legs works fine — and let your child fill it with zigzag stripes. Say 'zig, zag, zig' as the crayon turns. Z sounds and pre-writing lines together."}]},{"day":"Wednesday","focus":"Mamas & Babies","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Match the Babies","d":"Draw or gather pictures of animals and their babies, mix them up, and match: cow and calf, dog and puppy, hen and chick. Matching pairs is early math thinking."},{"t":"Count the Chicks","d":"Draw a mother hen and count out eight cotton-ball or paper chicks for her nest. Then add one or take one away — 'How many now?' Little change-the-number games build real number sense."}]},{"day":"Thursday","focus":"Egg to Grown","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Life Cycle Line-Up","d":"Draw three quick pictures — egg, chick, hen — and let your child put them in order, telling what happens at each step. First-next-last thinking powers both science and storytelling."},{"t":"Who Hatches?","d":"Play a sorting game: 'Does it hatch from an egg, or is it born like a puppy?' Try chicken, turtle, kitten, duck. Wrong guesses are welcome — wondering is the point."}]},{"day":"Friday","focus":"Gentle & Caring","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Baby Doll Care","d":"Set up baby care for a doll or stuffed animal: feed it, burp it, rock it, tuck it in with a whispered goodnight. Nurturing play grows empathy — and gentle big siblings."},{"t":"Baby Animal Story","d":"Read a baby-animal book together, or share baby photos of the pets and people in your own family. Ask, 'Who took care of you when you were a baby?'"}]}],"homeden":{"title":"The Home Den — This Week","lead":"Peep, waddle, and snuggle — a week of baby animals and gentle hands.","items":["Practice gentle touches on a pet or stuffed animal: 'Soft hands, like this.'","Buzz the letter Z at bath time — 'zzz' — and zigzag a finger through the water.","Name animal babies in books and on shirts: puppy, kitten, chick, cub.","Tell the story of your child as a baby — first foods, first steps. They never tire of it."]}},{"label":"Week 4 — Growing Me","days":[{"day":"Monday","focus":"How Tall Am I","domains":["Mathematical Thinking","Scientific Inquiry"],"opts":[{"t":"Doorway Measure","d":"Stand your child against a doorway, mark their height with tape, and measure it in blocks stacked from the floor. Write the date beside it — you will both want to check again."},{"t":"Bigger or Smaller","d":"Walk the house comparing: 'Are you taller than the chair? Smaller than the fridge?' Comparing sizes is measurement before rulers ever appear."}]},{"day":"Tuesday","focus":"Baby Me, Big Me","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Baby Photo Stories","d":"Look at your child's baby photos together and tell the stories behind them. Then ask, 'What can you do now that baby-you couldn't?' Family stories are a child's first history lessons."},{"t":"Then and Now Game","d":"Make a silly comparing game: 'When you were a baby you drank milk. Now you eat…' and let them shout the answer. Talking about change builds both language and identity."}]},{"day":"Wednesday","focus":"Strong Growing Body","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Can-Do Circuit","d":"Set up a mini course: hop over a sock, balance on one foot, crawl under the table, finish with a big jump. Cheer the trying, not just the finishing."},{"t":"One More Try","d":"Pick one tricky move — standing on one foot, a helped somersault — and practice it a little each day this week. Say, 'Your body is growing stronger every day.'"}]},{"day":"Thursday","focus":"Letter Round-Up","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"I, X, Z Round-Up","d":"Write I, X, and Z on paper scraps, scatter them around the room, and call out one letter at a time for your child to find and name. Three letters, big cheers, short attention spans respected."},{"t":"Body Letters","d":"Make the month's letters with your bodies: stand tall and straight for I, cross your arms for X, zigzag on the floor for Z. Letters you build with your whole body are hard to forget."}]},{"day":"Friday","focus":"Growing Self-Portrait","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"I Am Growing Portrait","d":"Have your child draw themselves doing something they just learned while you write the caption: 'I can pour my own milk.' Hang it low, at their height — pride you can point to."},{"t":"I Did It Reading","d":"Reread I Ride, I Slide or another favorite book and notice together how much smoother it feels than the first time. That feeling is growth — name it: 'You are growing as a reader.'"}]}],"homeden":{"title":"The Home Den — This Week","lead":"The best thing growing this month is your child — take a minute to notice together.","items":["Mark their height on a doorway and write the date next to it.","Swap 'you're so big' for 'look what you can do now' — it points pride at effort.","Trace the number 8 with a finger — two stacked circles, around and around.","Spot ovals — this month's shape — in eggs, spoons, and grapes at breakfast."]}}]},"apr":{"theme":"Our Big Blue Earth","weeks":[{"label":"Week 1 — Land & Water","days":[{"day":"Monday","focus":"Land or Water","domains":["Physical Development","Scientific Inquiry"],"opts":[{"t":"Land-Water Jump","d":"Lay a blue towel on the floor for water and call out 'land' or 'water' as your child jumps off or on — swimming arms in the water, stomping feet on land. Big moving makes big learning."},{"t":"Splash or Stomp Tubs","d":"Set a pan of water next to a pan of dirt or sand and let your child pat, poke, and compare — wet and squishy, dry and crumbly. Stay within arm's reach and collect every describing word they find."}]},{"day":"Tuesday","focus":"Sort the Animals","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Land or Water Animals","d":"Gather toy animals or draw quick ones and sort them into two piles: lives on land, lives in water. Where does a duck go? Both piles is a wonderful answer."},{"t":"Nine Teal Fish","d":"Draw nine simple fish — April's number is nine — and count them as your child colors each one teal or blue. Coloring while counting doubles the learning."}]},{"day":"Wednesday","focus":"Y Is for Yes","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Yyy Yes Sound","d":"Practice the letter Y — 'yyy' like yes, you, and yellow — then play a silly yes-or-no game: 'Do fish swim? Do cows fly?' Shouting the right answer never gets old."},{"t":"Bear Reader Time","d":"Read this month's Bear Phonics book, I Try, I Fly, and find the letter Y on the pages together. Trying is this month's quiet lesson — 'You tried, and you did it.'"}]},{"day":"Thursday","focus":"Our Big Home","domains":["Social Studies","Scientific Inquiry"],"opts":[{"t":"Globe Gaze","d":"Look at a globe, a map, or a picture of Earth from space and find the blue and green. Say, 'The blue is water, the green and brown are land — and we live right here.'"},{"t":"What Earth Gives Us","d":"Walk outside or look out the window and name what Earth gives us: trees, dirt, sky, puddles, air. Wonder out loud — 'Isn't our Earth amazing?' Awe is caught, not taught."}]},{"day":"Friday","focus":"Blue-Green Earth Craft","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Torn-Paper Earth","d":"Tear blue and green paper into small bits and glue them onto a paper-plate Earth. Tearing strengthens the same finger muscles that will someday hold a pencil."},{"t":"Play-Dough Planet","d":"Squish blue and green play-dough — or two colors of any dough — into one marbled ball, your own little Earth. Squeezing and rolling is a hand workout disguised as play."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Welcome to Earth month — start big: our whole beautiful blue home.","items":["Find Earth's colors on a walk: something blue, something green, something brown.","Practice the letter Y — 'yyy' like yes — and listen for it in family names.","Count nine of anything at snack time — nine raisins, nine crackers.","At bath time, name where water lives: oceans, rivers, rain, and right here in the tub."]}},{"label":"Week 2 — Reduce, Reuse, Recycle","days":[{"day":"Monday","focus":"Recycle Sort Relay","domains":["Physical Development","Social Studies"],"opts":[{"t":"Bin Run","d":"Set out two boxes — paper here, plastic there — hand your child clean recyclables one at a time, and let them run each to the right bin. Sorting on the move sticks better than sorting still."},{"t":"Recycling Truck Watch","d":"On pickup day, watch the recycling truck together and talk about where it all goes: 'Those bottles get made into new things.' Community helpers include trucks."}]},{"day":"Tuesday","focus":"Count Recyclables","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Recycling Count","d":"Count clean cans, bottles, or boxes as you drop them in the bin — can you reach nine this week? Keep a tally on the fridge and add it up on Friday."},{"t":"Sort by Kind","d":"Spread clean recyclables on the floor and sort by what they are made of: paper, plastic, metal. Then count each pile and crown the biggest. Sorting by attribute is preschool math gold."}]},{"day":"Wednesday","focus":"Reuse Invention","domains":["Creative Expression","Scientific Inquiry"],"opts":[{"t":"Box Invention","d":"Give your child a clean box, cup, or carton headed for the bin and ask, 'What could this become?' Robot, boat, hat? Tape, crayons, and imagination do the rest."},{"t":"Shaker Makers","d":"Drop dried rice or beans into an empty bottle, seal the lid tight, and shake to make music. Try different fillings and listen close — do big beans sound different from little rice?"}]},{"day":"Thursday","focus":"Three R Words","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Say the Three R's","d":"Practice the big words with hand motions: reduce means hands shrink small, reuse means hands roll over, recycle means arms circle around. Vocabulary with motions attached stays learned."},{"t":"Earth Book Time","d":"Read The Earth Book, We Are Water Protectors, or any story about nature, and ask, 'How do they take care of the Earth?' Books plant ideas that grow into habits."}]},{"day":"Friday","focus":"Clean-Up Crew","domains":["Social & Emotional Development","Physical Development"],"opts":[{"t":"Two-Song Tidy","d":"Put on two songs and tidy one room together before the music ends. Finish with, 'You take care of our home — that's being responsible.'"},{"t":"Yard Sweep Helpers","d":"Head outside together and pick up sticks or stray litter in your own yard, with you carrying the bag. Working for a shared space builds proud, capable kids."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Little hands can take care of a big planet — one bottle at a time.","items":["Give your child the recycling job this week: they drop it in, every time.","Before tossing anything, ask together, 'Could this be something else first?'","Make turning off lights their special switch job when you leave a room.","Say the three R's with motions at dinner: reduce, reuse, recycle."]}},{"label":"Week 3 — Weather & Sky","days":[{"day":"Monday","focus":"Weather Watcher","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Sky Color Check","d":"Step outside or lean out the door and study today's sky together — bright blue, soft gray, or teal like April's color? Ask your child to pick the exact word that fits. Precise describing words are a scientist's first tool."},{"t":"Wind Watcher","d":"Tape a strip of paper or ribbon where you can see it from a window and check it through the day: still, fluttering, or dancing? You can't see wind, but you can see what it does — that's real science thinking."}]},{"day":"Tuesday","focus":"Graph the Weather","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Warm or Cool Tally","d":"Each day, ask your child to vote: did today feel warm or cool? Add a tally mark to the winning side and count both rows on Friday. A week of weather, turned into their very first data chart."},{"t":"Raindrop Race Count","d":"On a rainy day, watch drops race down the window and count nine of them sliding by. No rain? Count nine clouds, or nine seconds of wind moving the trees."}]},{"day":"Wednesday","focus":"Sky Dancing","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Sun, Rain, Wind Dance","d":"Call out weather and dance it: stretch wide for sun, patter fingers and stomp for rain, spin gently for wind, freeze for snow. Weather words plus wiggles equals learning."},{"t":"Cloud Shape Yoga","d":"Lie on your backs and make shapes the way clouds do — stretch long and thin, curl round and puffy. Slow shape-making builds balance and calm."}]},{"day":"Thursday","focus":"Calm in Storms","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Storm Watch Together","d":"When clouds roll in, watch from the window and narrate: 'The sky is getting dark. Here comes the rain.' Watching safely beside you turns scary storms into science."},{"t":"Thunder Breathing","d":"Practice a storm plan on a calm day: when it booms, we cuddle up and take slow smell-the-flower, blow-the-candle breaths. Practicing calm before you need it is how calm works."}]},{"day":"Friday","focus":"Paint the Sky","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Watercolor Sky","d":"Paint or crayon today's sky — teal-blue, cloud gray, sunset pink — then have your child tell you about it while you write their words underneath. Art plus their own story equals literacy."},{"t":"Moon Book & Crescent","d":"At bedtime, read a book about the sky or moon and draw a crescent — April's shape — together. Then peek out the window: what shape is the moon tonight?"}]}],"homeden":{"title":"The Home Den — This Week","lead":"Eyes to the sky this week — every window is a science lesson.","items":["Let your child give the morning weather report before breakfast.","Point out the crescent shape — in the moon, a banana, a smile.","On cloudy days, find shapes in the clouds together — no wrong answers.","Practice slow flower-and-candle breaths so they're ready when storms boom."]}},{"label":"Week 4 — Caring for Our Earth","days":[{"day":"Monday","focus":"Earth Helper Jobs","domains":["Social Studies","Physical Development"],"opts":[{"t":"Backyard Caretakers","d":"Take a caretaking walk in your yard or park: pick up sticks, pull a weed, pat soil around a plant. Say, 'People who care for the Earth are called caretakers — that's us.'"},{"t":"Water the Green","d":"Give your child a cup or watering can and let them water the plants, inside or out. A real job, done daily, tells them living things count on us."}]},{"day":"Tuesday","focus":"Count Green Deeds","domains":["Mathematical Thinking","Social & Emotional Development"],"opts":[{"t":"Green Deeds Chart","d":"Draw a leaf on a fridge paper each time someone helps the Earth — recycling, saving water, turning off lights. Count the leaves each night and aim for nine by Friday."},{"t":"Earth Promise Fingers","d":"Make three family Earth promises and count them on fingers at dinner: 'Did we keep promise one? Two? Three?' Keeping small promises builds big character."}]},{"day":"Wednesday","focus":"Save the Water","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Tap Off Test","d":"Brush teeth once with the tap running and once with it off, catching the running water in a cup. Look together at how much you saved — plants and fish need that water too."},{"t":"Puddle to Cloud","d":"After rain, visit a puddle in the morning and again later: it shrinks. Where did it go? Up to the clouds, to fall again someday — that circle is called the water cycle."}]},{"day":"Thursday","focus":"I Try for Earth","domains":["Language & Literacy","Approaches to Learning"],"opts":[{"t":"Y Review Round","d":"Review the letter Y — trace it, air-write it, spot it on labels — then celebrate all the letters your child knows now. A whole alphabet, nearly theirs."},{"t":"I Fly Finale","d":"Reread I Try, I Fly and let your child finish the lines they remember, ending with a proud 'I did it.' Trying hard is exactly how we care for everything — Earth included."}]},{"day":"Friday","focus":"Earth Day Poster","domains":["Creative Expression","Social Studies"],"opts":[{"t":"Our Earth Poster","d":"Make a family poster: a big Earth in the middle, drawings of how you help all around it. Hang it where visitors will see it — art with a message is a child's first advocacy."},{"t":"Handprint Earth","d":"Press blue and green painted handprints in a circle to make an Earth, then title it together: 'We take care of our Earth.' Little hands, big promise."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Wrap up Earth month the best way — by taking care of it together.","items":["Keep one Earth promise going all week: lights off, water saved, or recycling sorted.","Trace the number 9 and the letter Y side by side — both have long tails.","Let your child water one plant every day — their plant, their job.","Find teal — April's color — out in the world: pool water, toys, a favorite shirt."]}}]},"may":{"theme":"On the Move","weeks":[{"label":"Week 1 — Things That Go","days":[{"day":"Monday","focus":"Vehicle Words","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Sound Effects Garage","d":"Line up toy cars or draw a few together, then give each one its own sound — vroom, beep, chugga-chugga. Naming vehicles and their sounds grows vocabulary while it feels like pure play."},{"t":"Vroom and Guess","d":"Make a vehicle sound behind your back and let your child guess what it is, then swap turns. Listening closely and matching sounds to words is early reading work in disguise."}]},{"day":"Tuesday","focus":"Count the Wheels","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Parking Lot Ten","d":"Draw ten parking spaces on paper and number them 1 to 10. Your child parks a toy car in each space, saying the number out loud — counting to ten with a purpose."},{"t":"Wheel Count Walk","d":"Step outside or peek out a window and count wheels together — a bike has two, a car has four. See if you can reach ten wheels before heading back in."}]},{"day":"Wednesday","focus":"How Wheels Roll","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Roll It Test","d":"Gather a ball, a toy car, a block, and a spoon. Predict which will roll, then test each one across the floor. Round things roll — your child just discovered why wheels are circles."},{"t":"Pentagon or Circle","d":"Cut a paper circle and a five-sided pentagon, then try rolling each. The bumpy pentagon flops while the circle glides — a shape lesson and a science lesson in one."}]},{"day":"Thursday","focus":"Taking Turns Driving","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Red Light Game","d":"Play red light, green light down the hallway — go on green, freeze on red. Waiting for the signal builds the same self-control your child needs for taking turns all day."},{"t":"Who Drives What","d":"Talk about the drivers in your town — the bus driver, the mail carrier, the firefighter. Pretend to be each one and let your child ride along, then trade seats."}]},{"day":"Friday","focus":"Build a Vehicle","domains":["Creative Expression","Physical Development"],"opts":[{"t":"Box Car Build","d":"Turn a cardboard box into a car with paper-plate wheels and a drawn-on steering wheel. Sitting inside and steering through the living room makes the whole week's theme come alive."},{"t":"Ride and Read","d":"Park the box car and climb in together for story time. This month's Bear Phonics reader, Light, Right, High, is a perfect fit — those igh words shine when you read them side by side."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Tuck these in your pocket for a week of things that go.","items":["Sort toys into things with wheels and things without — a laundry basket makes a fine garage.","Count to ten every time you buckle up this week. Seatbelt clicks make great counting timers.","Point out one vehicle sound on every drive and name it together — siren, horn, rumble.","Keep the box car around all week. Pretend play gets richer the longer the prop stays out."]}},{"label":"Week 2 — On Land","days":[{"day":"Monday","focus":"Trains and Bikes","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Living Room Train","d":"Line up chairs in a row and chug around the house collecting stuffed-animal passengers. Big pretend movement like this builds coordination and story-telling at the same time."},{"t":"Sky Bike Pedals","d":"Lie on your backs and pedal your legs in the air like you are riding bikes up a hill — slow, then fast. Strong core muscles help with everything from climbing to sitting at circle time."}]},{"day":"Tuesday","focus":"Ramp Science","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Steeper Means Faster","d":"Lean a cookie sheet against a couch cushion and roll a toy car down. Raise the ramp higher and try again — your child will see with their own eyes that steeper means faster."},{"t":"How Far Rolls","d":"Mark where each car stops with a bit of masking tape, then compare — which rolled near, which rolled far. Measuring words like these are the roots of real math."}]},{"day":"Wednesday","focus":"Retell a Trip","domains":["Language & Literacy","Social Studies"],"opts":[{"t":"Our Trip Story","d":"After any outing, retell it together using first, next, and last — first we drove, next we shopped, last we came home. Retelling in order is a big pre-reading skill."},{"t":"Map to Grandma","d":"Draw a simple map of a route your child knows — home to school or to a grandparent's house. Talking about the places you pass helps your child understand their own neighborhood."}]},{"day":"Thursday","focus":"Road Rules","domains":["Social & Emotional Development","Approaches to Learning"],"opts":[{"t":"Paper Stop Sign","d":"Make a paper stop sign and take turns being the crossing guard while the other walks or drives a toy car. Stopping on cue is self-regulation practice dressed up as a game."},{"t":"Why Rules Talk","d":"While buckling in this week, ask your child why we wear seatbelts and stop at red lights. Letting them explain the why helps rules feel like protection, not bossing."}]},{"day":"Friday","focus":"Roads and Rainbows","domains":["Creative Expression","Mathematical Thinking"],"opts":[{"t":"Tape Road Town","d":"Lay masking-tape roads across the floor and add paper buildings your child colors in. Drive ten cars through town, counting each one as it parks."},{"t":"Rainbow Road Collage","d":"Tear strips of paper in rainbow colors and glue them into winding roads on one big sheet. Name each color as it goes down — this month's color is the whole rainbow."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Land travel week — here are four little extras for home.","items":["Read a truck or train book together this week — Little Blue Truck and Freight Train are family favorites.","Let your child be the navigator on one errand: ask which way at each familiar turn.","Practice the safe street habit: stop, hold hands, look both ways, then walk.","Save a cereal box — flattened boxes make great ramps and road bridges all week."]}},{"label":"Week 3 — On Water & Air","days":[{"day":"Monday","focus":"Row and Fly","domains":["Physical Development","Language & Literacy"],"opts":[{"t":"Blanket Boat Row","d":"Sit inside a blanket boat and row together while singing Row, Row, Row Your Boat. Add new travel words as you go — paddle, drift, ahoy — and watch them stick."},{"t":"Airplane Arms Airport","d":"Stretch arms wide and fly around the room, then land gently on a pillow runway. Call out soar, glide, and land so the moves and the words take off together."}]},{"day":"Tuesday","focus":"Float or Sink","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Sink or Float Ten","d":"Fill a big bowl and test ten safe items — spoon, cork, crayon, bottle cap. Stay within arm's reach the whole time, and count how many floaters you end up with."},{"t":"Foil Boat Cargo","d":"Shape a square of foil into a little boat, float it in the sink, and load it with dried pasta, one piece at a time, until it sinks — staying within arm's reach the whole time. Counting cargo turns kitchen-sink play into real math."}]},{"day":"Wednesday","focus":"Paper Pilots","domains":["Creative Expression","Approaches to Learning"],"opts":[{"t":"Paper Plane Tries","d":"Fold a simple paper airplane together and test-fly it down the hall. When it nose-dives, adjust the wings and try again — sticking with a tricky thing is this month's brave habit."},{"t":"Sail a Paper Boat","d":"Fold a paper boat and sail it in a sink or shallow bin, staying within arm's reach. Blow it gently across the water and watch how air makes things move."}]},{"day":"Thursday","focus":"Brave New Tries","domains":["Social & Emotional Development","Physical Development"],"opts":[{"t":"Bridge Over Water","d":"Lay a masking-tape line across the floor and pretend it is a bridge over water. Walk it heel to toe, arms out — wobbles welcome, because brave means trying even when it is tricky."},{"t":"I Tried It Cheer","d":"Pick one small new thing today — a new food, a new move, a new word — and give a big family cheer after the try, not just the success. That is how courage grows."}]},{"day":"Friday","focus":"Travel Talk","domains":["Social Studies","Mathematical Thinking"],"opts":[{"t":"Pack for Adventure","d":"Pretend-pack a bag for a boat or plane trip, counting up to ten items as they go in. Talk about where you would go and who you would visit — near or far."},{"t":"High in the Sky","d":"Snuggle up with the Bear Phonics reader Light, Right, High — the igh words fit a flying week perfectly. Let your child read the words they know and finish with a big high five."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Boats and planes this week — four simple ways to keep it afloat at home.","items":["Bath time is science time: bring two toys and ask float or sink before they splash down. Always stay within arm's reach.","Spot something in the sky each day — plane, bird, or cloud — and describe it together.","Practice the word brave: name one brave try your child made today at dinner.","Keep folding paper boats and planes — folding paper is quiet fine-motor gold."]}},{"label":"Week 4 — How I Move","days":[{"day":"Monday","focus":"Move Stations","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Living Room Obstacle","d":"Set up three stations — jump over a pillow, crawl under the table, balance along a tape line. Doing the course in order builds body control and remembering-what-comes-next."},{"t":"Spin and Freeze","d":"Turn on music and dance with spins, then freeze when it stops. Freezing mid-move takes real self-control — and it is even funnier when a grown-up wobbles too."}]},{"day":"Tuesday","focus":"Count Our Jumps","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Jump to Ten","d":"Count out loud together while your child does ten big jumps, then ten hops on one foot. Counting while moving helps numbers sink into the body, not just the head."},{"t":"Our Move Graph","d":"Make three columns on paper — jumps, spins, hops — and add a tally mark each time your child does one. At the end, count the marks and see which move won."}]},{"day":"Wednesday","focus":"Action Words","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Alphabet Actions","d":"Call out a letter and do a move that starts with it — B bounce, C crawl, S stomp, T tiptoe. It is a whole-body alphabet review, perfect for this month's A to Z."},{"t":"Read and Act","d":"Read a favorite book together, then act out its action words — hop like the bunny, march like the band. Acting out a story helps your child remember and retell it."}]},{"day":"Thursday","focus":"Muscles at Work","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Feel Your Muscles","d":"Do ten jumps, then put a hand on your heart and feel it thump. Squeeze arm muscles like a strongman and talk about how muscles and hearts help us move."},{"t":"I Can Move Cheer","d":"Have your child name one move they could not do as a baby but can do now — then celebrate it. Noticing their own growing power builds honest confidence."}]},{"day":"Friday","focus":"Dance and Paint","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Dance Paint Party","d":"Tape paper to the table, turn on music, and let crayons dance — fast scribbles for fast songs, slow swirls for slow ones. Use every rainbow color you can find."},{"t":"Family Move Show","d":"Everyone in the family shows off one signature move while the rest clap and cheer. Being the performer and the audience are both big social skills for a three-year-old."}]}],"homeden":{"title":"The Home Den — This Week","lead":"A whole week of wiggles — keep these moving at home.","items":["Count ten of something every day — stairs, jumps, blueberries, buttons.","Play one round of freeze dance before bath time to shake out the last wiggles.","Say it in the mirror together: I can move, I can learn, I can do hard things.","Look for pentagons and rainbows out and about this week — five-sided shapes hide everywhere."]}}]},"jun":{"theme":"Sun, Sand & Splash","weeks":[{"label":"Week 1 — At the Beach","days":[{"day":"Monday","focus":"Beach Words","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Blanket Beach Day","d":"Spread a towel on the floor, put on pretend sunscreen, and set up a living-room beach. Name every beach word you can — sand, shell, wave, tide — while you play."},{"t":"Shell Collage Art","d":"Glue pasta shells or torn paper shells onto a sheet in a swirling wave design. Add a strip of aqua paper for the sea — that is this month's color, so say it often."}]},{"day":"Tuesday","focus":"Sort the Shells","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Seashell Sort Shop","d":"Pour out pasta shells or bottle caps and sort them by big and small, then count each pile. Sticking with a sort to the very last shell builds focus — stay close while the small pieces are out."},{"t":"Count to Eleven","d":"This month's number is 11 — one more than ten fingers. Line up eleven shells or blocks, count them slowly, and let your child discover which one has no finger to match."}]},{"day":"Wednesday","focus":"Wet Sand Science","domains":["Scientific Inquiry","Physical Development"],"opts":[{"t":"Wet vs Dry Lab","d":"Put dry oatmeal in two bowls and add water to one. Which packs into a ball, which pours like a waterfall? That is exactly how beach sand works too."},{"t":"Hot Sand Tiptoe","d":"Pretend the floor is hot summer sand and tiptoe fast between pillow islands. Tiptoe travel strengthens little feet and legs — and the giggles are free."}]},{"day":"Thursday","focus":"Beach Feelings","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Wave Breathing","d":"Lie on your beach towel and breathe like waves — slow breath in as the wave rises, long breath out as it rolls away. Calm-down tools work best when you practice them happy."},{"t":"Lifeguard Helpers","d":"Talk about who keeps swimmers safe at the beach and pool — lifeguards. Take turns being the lifeguard who watches over the stuffed-animal swimmers."}]},{"day":"Friday","focus":"Beach Pretend Play","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Beach Trip Script","d":"Act out a whole beach day — pack the bag, drive, swim, snack, nap under the umbrella. Pretend play with a beginning, middle, and end is storytelling on its feet."},{"t":"Ocean Story Time","d":"Read an ocean book together — Hello Ocean is a lovely pick. Hunt the pages for the color aqua and for letters your child knows from the A to Z review."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Beach week starts here — four easy waves to ride at home.","items":["Practice one water-safety rule together: we only swim when a grown-up is watching, always.","Count seashells, crackers, or buttons up to 11 — this month's number — once a day.","Find something aqua at home or in the store and let your child name the color.","Build a beach for stuffed animals from a towel shore and a blue blanket sea, and pack them a pretend beach bag."]}},{"label":"Week 2 — In the Water","days":[{"day":"Monday","focus":"Swim Moves","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Dry Land Swim","d":"Lie tummy-down on a couch cushion and practice big swim arms and kicks. Strong arm circles build the shoulder muscles that later hold pencils steady."},{"t":"Pour Together Turns","d":"Set up cups at the sink and take turns pouring for each other — you hold, I pour, then switch. Water play is happiest when cooperation leads, and stay within arm's reach."}]},{"day":"Tuesday","focus":"Guess Then Test","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Predict the Splash","d":"Before each item goes in the water bin, ask for a prediction: float or sink? Guessing first, then testing, is the real scientist's habit — and stay within arm's reach."},{"t":"Which Holds More","d":"Set out a tall skinny cup and a short wide bowl and ask which holds more water, then pour to find out. Guessing first, testing second — and staying within arm's reach — is how little scientists work."}]},{"day":"Wednesday","focus":"Pour and Measure","domains":["Mathematical Thinking","Physical Development"],"opts":[{"t":"Cup Count Kitchen","d":"At the sink, count how many little cups of water it takes to fill one big cup. Pouring carefully is measuring, math, and hand-strength practice all at once."},{"t":"Eleven Scoops","d":"Scoop water into a big bowl with a measuring cup, counting each scoop up to eleven. Stop and admire the water line — that is what eleven scoops looks like."}]},{"day":"Thursday","focus":"Water Words","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Splash Sound Words","d":"Collect splashy words at bath or sink time — drip, splash, pour, bubble, swish. Say each one the way it sounds and let your child invent a brand-new water word."},{"t":"He Eats Meat","d":"Read this month's Bear Phonics reader, He Eats Meat, together. Let your child read every word they can, then finish with a proud I did it — celebrating effort makes readers."}]},{"day":"Friday","focus":"Fish and Boats","domains":["Creative Expression","Social Studies"],"opts":[{"t":"Fish Handprint","d":"Trace or paint your child's hand, turn it sideways, and add an eye and bubbles — a handprint fish. Hang it low so your child can show it off to visitors."},{"t":"Working Boats Talk","d":"Talk about boats that do jobs — ferry boats carry people, fishing boats bring food, tugboats help big ships. Then float a plastic-lid ferry full of tiny passengers."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Water week — keep the learning flowing between splashes.","items":["Add two measuring cups to every bath this week. Pouring practice is free math.","Do one sink-or-float guess at bath time — prediction first, splash second.","Remember the golden rule: water play always happens within arm's reach of a grown-up.","Reread He Eats Meat before bed once this week — repeat readings build confident readers."]}},{"label":"Week 3 — Sun & Sky","days":[{"day":"Monday","focus":"Shadow Science","domains":["Scientific Inquiry","Mathematical Thinking"],"opts":[{"t":"Shadow Trace Compare","d":"Trace your child's shadow with chalk or tape in the morning, then again in the afternoon. Compare the two — longer or shorter? The sun moved, and the proof is on the ground."},{"t":"Cloud Count Blanket","d":"Stretch out on a blanket and count clouds together, aiming for eleven. Describe each one — puffy, stretched, gray — before it drifts away."}]},{"day":"Tuesday","focus":"Sun Safety","domains":["Social Studies","Social & Emotional Development"],"opts":[{"t":"Pack the Sun Kit","d":"Pack a real sun kit together — hat, sunscreen, water bottle — and talk about why each one protects us. Your child becomes the family sun-safety helper all summer."},{"t":"Shade Break Practice","d":"Practice a calm shade break: find a shady spot, sip water, and rest for a few slow breaths. Learning to notice I am hot and I need rest is real self-care for a three-year-old."}]},{"day":"Wednesday","focus":"Chase and Freeze","domains":["Physical Development","Approaches to Learning"],"opts":[{"t":"Sunshine Freeze Tag","d":"Play a gentle chase game where the sun says freeze — run until the caller shouts it, then hold statue-still. Stopping a moving body on cue is powerful practice."},{"t":"Shadow Copycat","d":"Stand in the sun and copy each other's shadow shapes — star arms, flamingo leg, tiny ball. Watching a shadow obey your body never stops being amazing."}]},{"day":"Thursday","focus":"Sky Words","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Sky Word Watch","d":"Look up together and collect sky words — bright, breezy, glowing, gray. Ask which letter sun starts with, then hunt for more S words hiding in your day."},{"t":"Shady Story Time","d":"Take a book to the shadiest spot you can find — under a tree or a blanket fort — and read together. A cozy reading spot makes books feel like a treat, not a task."}]},{"day":"Friday","focus":"Sunshine Art","domains":["Creative Expression","Social & Emotional Development"],"opts":[{"t":"Sun and Sky Painting","d":"Draw or paint a big warm sun in an aqua sky, then add anything else the sky holds — clouds, birds, a rainbow. Talk about how sunny days make us feel while you work."},{"t":"You Are My Sunshine","d":"Learn You Are My Sunshine and sing it to someone your child loves — in person or on a call. Singing to someone is a small, brave act of love."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Sun and sky week — four bright ideas for home.","items":["Make hat-and-sunscreen part of the going-outside routine, with your child as checker.","Find your shadows together once this week — morning and evening — and compare.","Keep a water bottle where your child can reach it and praise every self-serve sip.","Describe the sky at breakfast each day: sunny, cloudy, gray, or glowing."]}},{"label":"Week 4 — Summer Play","days":[{"day":"Monday","focus":"Backyard Games","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Sock Toss Relay","d":"Tape a circle, a square, and a triangle on the floor and toss rolled socks into each shape target. Shape review and throwing practice, one sock at a time."},{"t":"Everyone Plays Rule","d":"Before any game this week, say the family rule together: everyone who wants to play, plays. Practice inviting a sibling or stuffed animal in with the words come play with us."}]},{"day":"Tuesday","focus":"Graph Our Fun","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Favorite Play Vote","d":"Let the family vote — sprinkler, bubbles, or tag? Make a tally column for each and count which wins. Your child just made a real graph about real life."},{"t":"Summer Fun Retell","d":"After a fun moment, ask your child to tell it back in order — first, next, last. Retelling their own day is the friendliest storytelling practice there is."}]},{"day":"Wednesday","focus":"Why Water Helps","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Hot Body Science","d":"Do twenty big jumps, then notice together — warm cheeks, thumping heart, thirsty mouth. Take a long drink and talk about how water cools our bodies from the inside."},{"t":"Ice Melt Race","d":"Set one ice cube in the sun and one in the shade and check back to see which melts first. Guess before you look — that is the scientist's way."}]},{"day":"Thursday","focus":"Share and Include","domains":["Social & Emotional Development","Social Studies"],"opts":[{"t":"Share Basket Pick","d":"Have your child choose a few toys to lend a friend or give away to another child. Choosing what to share, all by themselves, makes generosity feel like their own idea."},{"t":"Summer Helpers Talk","d":"Talk about the people who keep summer safe and fun — lifeguards, ice-cream sellers, park workers. Wave and say thank you when you meet one this week."}]},{"day":"Friday","focus":"Summer Memories","domains":["Creative Expression","Language & Literacy"],"opts":[{"t":"Memory Painting Day","d":"Paint or draw a favorite summer moment so far — the sprinkler, the beach blanket, the melty popsicle. Write your child's words under the picture as they tell you about it."},{"t":"Read Then Draw","d":"Read a favorite summer book together, then draw the best part. Going from listening to drawing shows your child that stories live on after the last page."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Summer play week — four keepers for the fridge door.","items":["Start a summer bucket list together and draw a picture for each idea.","Water first, play second: a drink before outdoor play beats a meltdown later.","Sing the ABC song in a silly voice each day — the A to Z review loves a giggle.","Save this week's memory painting — it will be a treasure by August."]}}]},"jul":{"theme":"Imagination Station","weeks":[{"label":"Week 1 — Once Upon a Time","days":[{"day":"Monday","focus":"Act It Out","domains":["Physical Development","Language & Literacy"],"opts":[{"t":"Three Bears Theater","d":"Act out a favorite story with your whole bodies — stomp like Papa Bear, tiptoe like Goldilocks. Playing the parts helps your child hold the story's words and order in memory."},{"t":"Troll Bridge Crossing","d":"Line up couch cushions as a bridge and take turns being the goats trip-trapping across while the troll listens below. Big dramatic play builds big language."}]},{"day":"Tuesday","focus":"First Next Last","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Story Order Cards","d":"Draw three quick pictures from a story your child knows — beginning, middle, end. Mix them up and let your child put them back in order, saying first, next, last."},{"t":"Snack in Order","d":"Make a simple snack together and narrate the steps in order — first we wash hands, next we spread, last we eat. Sequencing a real task makes the idea stick."}]},{"day":"Wednesday","focus":"Real or Pretend","domains":["Scientific Inquiry","Social & Emotional Development"],"opts":[{"t":"Real or Pretend Quiz","d":"Play a sorting game with silly questions — can a fish ride a bike? Can a dog bark? Deciding what is real and what is pretend is genuine three-year-old science."},{"t":"Feelings in Stories","d":"At story time tonight, pause and ask how the character feels — happy, scared, mad? Naming feelings in a story is safe practice for naming their own."}]},{"day":"Thursday","focus":"Make a Story","domains":["Language & Literacy","Creative Expression"],"opts":[{"t":"Story Starter Game","d":"Begin with once upon a time there was a purple bear, then let your child add what happens next. Take turns line by line until the story finds its ending."},{"t":"Draw Your Story","d":"Have your child draw their own story, then tell it to you while you write their words underneath. Seeing their spoken words become print is a reading milestone."}]},{"day":"Friday","focus":"Story Celebration","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Family Story Night","d":"Ask a grandparent or relative to tell a story from when they were little — in person or on a call. Family stories teach children where they come from."},{"t":"Change the Ending","d":"Read a favorite book together, then invent a brand-new ending and act it out. Playing with a story shows your child that they can be an author too."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Story week — four ways to keep once upon a time going at home.","items":["Fold a sheet of paper into a mini book and let your child fill it with their own story.","Use first, next, and last out loud during one routine each day.","Ask what happens next at a cliffhanger moment in every bedtime book.","Keep a story jar: drop in little pictures or objects and pull one to start a tale."]}},{"label":"Week 2 — Make-Believe & Dress-Up","days":[{"day":"Monday","focus":"Character Moves","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Move Like Magic","d":"Call out characters and move like each one — stomp like a giant, flutter like a fairy, creep like a cat. Switching bodies on cue is imagination and exercise in one."},{"t":"Animal Costume Parade","d":"March a pretend parade where everyone is a different animal — change animals when the leader claps. Let your child take a turn as the clapping leader."}]},{"day":"Tuesday","focus":"Sort the Props","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Prop Sort Shop","d":"Pile up dress-up bits — hats, scarves, old shirts — and sort them by color or by who might wear them. Sorting by an attribute is math thinking in costume."},{"t":"Twelve Treasure Props","d":"This month's number is 12. Collect twelve pretend props into a treasure box, counting each one in, then count them all back out at cleanup."}]},{"day":"Wednesday","focus":"What Could This Be","domains":["Scientific Inquiry","Creative Expression"],"opts":[{"t":"Box Transformation","d":"Set out an empty cardboard box and ask, what could this become? Test the best ideas — rocket, cave, drum, boat. Imagining and then building is exactly how inventors work."},{"t":"Spoon Puppet Make","d":"Turn a wooden spoon into a puppet with a drawn-on face and a scrap-fabric cape. Then let the puppet introduce itself to the family in its own voice."}]},{"day":"Thursday","focus":"Role-Play Talk","domains":["Language & Literacy","Social & Emotional Development"],"opts":[{"t":"Restaurant Pretend","d":"Open a pretend restaurant — your child takes your order on a notepad, serves invisible soup, and asks how everything tastes. Role-play dialogue stretches sentences beautifully."},{"t":"I Can Be Anything","d":"Let your child dress as whoever they want to be and announce it proudly: I can be a builder, a doctor, a dancer. Say it back to them like you believe it — because you do."}]},{"day":"Friday","focus":"Helper Dress-Up","domains":["Social Studies","Language & Literacy"],"opts":[{"t":"Community Helper Day","d":"Dress up as community helpers — firefighter, mail carrier, doctor — and act out one job each. Talk about how each helper takes care of your town."},{"t":"Read in Costume","d":"Stay in costume for story time and read this month's Bear Phonics reader, The Deer Sees Seeds — bonus points for deer antler hands. Reading in character makes the words an event."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Dress-up week — the imagination station is open at home too.","items":["Fill one bin with old hats, scarves, and shirts — a dress-up box needs nothing fancy.","Ask who are you today? when pretend play starts, then play along with the answer.","Count to 12 while tidying props back into their box each evening.","Save every big cardboard box this month — each one is a costume or a castle waiting."]}},{"label":"Week 3 — Art & Music","days":[{"day":"Monday","focus":"Dance to Music","domains":["Physical Development","Creative Expression"],"opts":[{"t":"Fast Slow Dance","d":"Play one fast song and one slow song and match your dancing to each. Feeling the difference in their whole body teaches tempo better than any explanation."},{"t":"Scarf Symphony","d":"Hand out scarves or clean socks and wave them to the music — high, low, swirling, still. Add a purple one if you can; purple is this month's color."}]},{"day":"Tuesday","focus":"Patterns Everywhere","domains":["Mathematical Thinking","Approaches to Learning"],"opts":[{"t":"Clap Pattern Band","d":"Start a pattern — clap, clap, stomp — and keep it going together until it falls apart in giggles. Then let your child invent the next pattern for you to copy."},{"t":"Cup Stamp Patterns","d":"Dip a cup rim in paint and stamp circles in a repeating pattern — purple, white, purple, white. Patterns in art are the same patterns math is built on."}]},{"day":"Wednesday","focus":"How Sound Works","domains":["Scientific Inquiry","Language & Literacy"],"opts":[{"t":"Kitchen Band Lab","d":"Make shakers from tightly sealed containers of dried pasta and rice, then test them — which is loudest, which is softest? Comparing sounds is ear science."},{"t":"Sound Word Safari","d":"Walk the house listening for sounds — the hum of the fridge, the tick of a clock — and find a word for each one. Describing sounds builds rich, precise vocabulary."}]},{"day":"Thursday","focus":"Art Shows Feelings","domains":["Social & Emotional Development","Creative Expression"],"opts":[{"t":"Feelings Color Painting","d":"Ask your child to pick a color for how they feel today and paint with it — sunny yellow, calm blue, proud purple. Art gives big feelings a safe place to land."},{"t":"Point to the Feeling","d":"Read Your Feelings Matter together — Mrs. Bear's own book — and let your child point to the feeling that matches their day. Then draw that feeling as a face."}]},{"day":"Friday","focus":"Art Show Day","domains":["Social Studies","Physical Development"],"opts":[{"t":"Family Art Museum","d":"Tape the week's artwork along a wall and lead the family on a museum tour, with your child as the guide. Museums are how communities share what they make."},{"t":"World Music Dance","d":"Play songs from different parts of the world and dance to each one. Talk about how music comes from everywhere, and every place has its own beat."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Art and music week — keep the studio open between meals.","items":["Keep crayons and scrap paper on the table all week — invitation beats instruction.","Have a two-song dance party before dinner: one fast, one slow.","Ask tell me about your art instead of what is it — then write their words on the back.","Spot purple somewhere new each day — this month's color hides in plain sight."]}},{"label":"Week 4 — Dream Big","days":[{"day":"Monday","focus":"Superhero Moves","domains":["Physical Development","Social & Emotional Development"],"opts":[{"t":"Hero Training Course","d":"Build a superhero training course — leap the pillow lava, crawl the table tunnel, rescue a stuffed animal at the end. Finishing a hard course is confidence you can feel."},{"t":"Cape and Cheer","d":"Clip on a towel cape and strike a hero pose while saying this month's words: my ideas matter. Say it back with their name in it — Maya's ideas matter."}]},{"day":"Tuesday","focus":"Count Big Ideas","domains":["Mathematical Thinking","Language & Literacy"],"opts":[{"t":"Twelve Dream List","d":"Make a list of twelve things your child dreams of trying — ride a horse, bake a cake, see the ocean. Count the dreams together as you write each one down."},{"t":"When I Grow Up","d":"Take turns finishing the sentence when I grow up I will… — grown-ups play too. Follow-up questions like what will you need? stretch the thinking further."}]},{"day":"Wednesday","focus":"Inventors Build","domains":["Scientific Inquiry","Approaches to Learning"],"opts":[{"t":"Invent a Machine","d":"Imagine a machine your family needs — a cookie maker, a toy finder — then build it from boxes, tubes, and tape. Inventors imagine first and build second, just like this."},{"t":"Fix It Challenge","d":"Present a problem: the stuffed animals need a bridge between two chairs. Offer materials and let your child try, wobble, and try again. The redesign is where the learning lives."}]},{"day":"Thursday","focus":"Big Dream Jobs","domains":["Social Studies","Creative Expression"],"opts":[{"t":"Interview a Grown-Up","d":"Help your child interview a family member about their job — what do you do, what is the best part? Learning about work is learning how a community fits together."},{"t":"Invention Drawing","d":"Draw the dream invention from this week in glorious detail — purple crayon encouraged. Label the parts with your child's words so the plan is official."}]},{"day":"Friday","focus":"Dream Celebration","domains":["Social & Emotional Development","Language & Literacy"],"opts":[{"t":"I Did It Wall","d":"Make a little wall display of things your child learned this year, A to Z where you can — B for buttons, C for counting. Reviewing the alphabet through their own wins is the sweetest kind of practice."},{"t":"Magnificent Story Time","d":"Read The Most Magnificent Thing or another try-again tale, and talk about how the character kept going. End with one dream your child wants to chase next."}]}],"homeden":{"title":"The Home Den — This Week","lead":"Dream-big week — four small ways to grow big ideas at home.","items":["Say my ideas matter in the mirror together once a day this week.","Keep the dream list on the fridge and check off any dream you try together.","Offer tape, boxes, and time — the best invention kit costs nothing.","At bedtime, ask what will you dream about tonight? and listen all the way to the end."]}}]}};